function normalizeClient(row) {
  if (!row) return null;
  if (typeof row === "string") return { 거래처명: row, 사업자번호: "", 사업자명: "", 메모: "" };
  return {
    거래처명: row.거래처명 || row.name || row.상호 || row.회사명 || row.title || "",
    사업자번호: row.사업자번호 || row.사업자등록증 || row.사업자등록번호 || "",
    사업자명: row.사업자명 || row.대표자 || row.대표자명 || row.ceo || "",
    메모: row.메모 || row.memo || "",
    대표자: row.대표자 || row.사업자명 || "",
    업태: row.업태 || "",
    종목: row.종목 || "",
    주소: row.주소 || "",
    담당자: row.담당자 || "",
    연락처: row.연락처 || "",
    이메일: row.이메일 || row.email || "",
  };
}
function normalizeClients(arr) {
  if (!Array.isArray(arr)) return [];

  return arr
    .map(normalizeClient)
    .filter(c => c && c.거래처명)
    .map(c => ({
      id: c.id || c.거래처명,
      거래처명: c.거래처명 || "",
      사업자번호: c.사업자번호 || "",
      대표자: c.대표자 || "",
      업태: c.업태 || "",
      종목: c.종목 || "",
      주소: c.주소 || "",
      담당자: c.담당자 || "",
      연락처: c.연락처 || "",
      이메일: c.이메일 || "",
      메모: c.메모 || ""
    }));
}
