export const toInt = (v) => {
  const n = parseInt(String(v ?? "0").replace(/[^\d-]/g, ""), 10);
  return isNaN(n) ? 0 : n;
};
export const fmtWon = (n) => `${Number(n || 0).toLocaleString()}원`;
// 📌 전화번호 하이픈 자동 적용 함수
function formatPhone(phone) {
  const p = String(phone ?? "").replace(/[^\d]/g, "");

  if (p.length === 11) {
    return `${p.slice(0, 3)}-${p.slice(3, 7)}-${p.slice(7)}`;
  }
  if (p.length === 10) {
    return `${p.slice(0, 3)}-${p.slice(3, 6)}-${p.slice(6)}`;
  }

  return p;
}
function makeFullDetailText(r) {

  const pickupTime = r.상차시간?.trim() || "즉시";
  const dropTimeRaw = r.하차시간?.trim() || "즉시";

  const plate = r.차량번호 || "-";
  const name = r.이름 || "-";
  const phone = formatPhone(r.전화번호 || "");

  const fare = Number(r.청구운임 || 0);
  const payLabel = r.지급방식 || "";

  // =====================
  // 요일 계산
  // =====================
  const yoilList = ["일요일","월요일","화요일","수요일","목요일","금요일","토요일"];
  let yoil = "";

  if (r.상차일) {
    const d = new Date(r.상차일);
    yoil = yoilList[d.getDay()];
  }

  // =====================
  // 하차 날짜 계산
  // =====================
  let dateNotice = "";
  let dropTimeText = dropTimeRaw;

  if (r.상차일 && r.하차일) {

    const s = new Date(r.상차일);
    const e = new Date(r.하차일);

    const s0 = new Date(s.getFullYear(), s.getMonth(), s.getDate());
    const e0 = new Date(e.getFullYear(), e.getMonth(), e.getDate());

    const diffDays = Math.round(
      (e0 - s0) / (1000 * 60 * 60 * 24)
    );

    const sm = s.getMonth() + 1;
    const sd = s.getDate();

    const em = e.getMonth() + 1;
    const ed = e.getDate();

    if (diffDays === 1) {

      dateNotice =
        `익일 하차 건 (상차: ${sm}/${sd} → 하차: ${em}/${ed})\n\n`;

      dropTimeText =
        `${em}/${ed} ${dropTimeRaw}`;

    }

    else if (diffDays >= 2) {

      dateNotice =
        `지정일 하차 건 (상차: ${sm}/${sd} → 하차: ${em}/${ed})\n\n`;

      dropTimeText =
        `${em}/${ed} ${dropTimeRaw}`;

    }

  }

  // =====================
  // 메시지 생성
  // =====================
  return `${dateNotice}${r.상차일 || ""} ${yoil}

상차지 : ${r.상차지명 || "-"}
${r.상차지주소 || "-"}${
  r.상차지담당자 || r.상차지담당자번호
    ? `\n담당자 : ${r.상차지담당자 || ""}${
        r.상차지담당자번호
          ? ` (${formatPhone(r.상차지담당자번호)})`
          : ""
      }`
    : ""
}
상차시간 : ${pickupTime}
상차방법 : ${r.상차방법 || "-"}

하차지 : ${r.하차지명 || "-"}
${r.하차지주소 || "-"}${
  r.하차지담당자 || r.하차지담당자번호
    ? `\n담당자 : ${r.하차지담당자 || ""}${
        r.하차지담당자번호
          ? ` (${formatPhone(r.하차지담당자번호)})`
          : ""
      }`
    : ""
}
하차시간 : ${dropTimeText}
하차방법 : ${r.하차방법 || "-"}

중량 : ${r.차량톤수 || "-"}${r.화물내용 ? ` / ${r.화물내용}` : ""} ${r.차량종류 || ""}

${plate} ${name} ${phone}
${fare.toLocaleString()}원 ${payLabel} 배차되었습니다.`;

}
// 차량번호 정규화 (공백 / 하이픈 제거 + 소문자)
function normalizePlate(v = "") {
  return String(v)
    .toLowerCase()
    .replace(/\s/g, "")
    .replace(/-/g, "");
}
// ================================
// 경유지 포함 화물내용+톤수 합산 헬퍼 (모듈 스코프)
// ================================
function _parseWaypointList(v) {
  if (Array.isArray(v) && v.length > 0) return v;
  if (typeof v === "string" && v.trim().startsWith("[")) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p; } catch {}
  }
  if (v && typeof v === "object" && !Array.isArray(v)) {
    const ks = Object.keys(v);
    if (ks.length > 0 && ks.every(k => /^\d+$/.test(k)))
      return ks.sort((a, b) => Number(a) - Number(b)).map(k => v[k]);
    if (v.업체명) return [v];
  }
  return [];
}
function mergeViaCargoText(mainCargo, waypointLists) {
  const mainStr = String(mainCargo || "").trim();
  const UNITS = ["파렛트", "파레트", "팔레트", "파렛", "파레", "박스", "통", "바구니"];
  const NORM = { "파렛트": "파레트", "팔레트": "파레트", "파렛": "파레트", "파레": "파레트" };
  const getType = (s) => {
    for (const u of UNITS) { if (String(s).endsWith(u)) return NORM[u] || u; }
    return null;
  };
  const getNum = (s) => { const m = String(s).match(/^([\d,.]+)/); return m ? parseFloat(m[1].replace(/,/g, "")) : null; };
  const allCargos = [];
  if (mainStr && mainStr !== "없음") allCargos.push(mainStr);
  let hasViaWithCargo = false;
  for (const list of waypointLists) {
    for (const s of _parseWaypointList(list)) {
      if (!s) continue;
      const wCargo = String(s.화물내용 || "").trim();
      if (!wCargo || wCargo === "없음") continue;
      const isTypeOnly = UNITS.some(u => wCargo === u || wCargo === (NORM[u] || u));
      if (isTypeOnly) continue;
      allCargos.push(wCargo);
      hasViaWithCargo = true;
    }
  }
  if (!hasViaWithCargo) return mainStr;
  const byUnit = {};
  const untyped = [];
  for (const cargo of allCargos) {
    const type = getType(cargo);
    if (type !== null) {
      const n = getNum(cargo);
      if (n !== null) { byUnit[type] = (byUnit[type] || 0) + n; }
      else if (!untyped.includes(cargo)) untyped.push(cargo);
    } else {
      if (!untyped.includes(cargo)) untyped.push(cargo);
    }
  }
  const parts = [...Object.entries(byUnit).map(([u, n]) => `${n}${u}`), ...untyped];
  return parts.join("+");
}
function mergeViaTonnage(mainTon, waypointLists) {
  const parseKg = (s) => {
    const str = String(s || "").trim().replace(/,/g, "");
    const kg = str.match(/([\d.]+)\s*kg/i);
    if (kg) return parseFloat(kg[1]);
    const ton = str.match(/([\d.]+)\s*톤/);
    if (ton) return parseFloat(ton[1]) * 1000;
    return null;
  };
  const fmtKg = (kg) => {
    if (kg >= 1000) return (kg / 1000).toFixed(3).replace(/\.?0+$/, "") + "톤";
    return Math.round(kg).toLocaleString() + "kg";
  };
  const mainKg = parseKg(mainTon);
  let totalKg = mainKg || 0;
  let hasViaWithTon = false;
  for (const list of waypointLists) {
    for (const s of _parseWaypointList(list)) {
      if (!s) continue;
      const t = String(s.차량톤수 || "").trim();
      if (!t) continue;
      const kg = parseKg(t);
      if (kg !== null) { totalKg += kg; hasViaWithTon = true; }
    }
  }
  if (!hasViaWithTon) return mainTon || "";
  if (totalKg <= 0) return mainTon || "";
  return fmtKg(totalKg);
}

