    if (pu) { seen.add(pu._id); out.push(pu); }
    // 하차지로 매칭되는 것 1건 (다른 레코드)
    const dr = copyList.find(r => !seen.has(r._id) && String(r.하차지명||"").toLowerCase().includes(q));
    if (dr) out.push(dr);
    // 둘 다 없으면 그냥 첫 번째
    return out.length ? out : [copyList[0]];
