                    const names = [...new Set([..._xv(r.경유지_상차),..._xv(r.경유상차목록),..._xv(r.경유지상차),..._xv(r.경유지_하차),..._xv(r.경유하차목록),..._xv(r.경유지하차)])];
                    if (!names.length) return null;
