// ✅ 배차상태 우선순위: 배차중 -> 배차완료 -> 배차취소(맨 아래)
// ✅ 배차상태 우선순위: 배차중 -> 배차완료 -> 배차취소(맨 아래)
const getStatusRank = (s) => {
  const v = String(s || "");
  if (v === "배차중") return 0;
  if (v === "배차완료") return 1;
  if (v === "배차취소") return 2;
  return 3;
};

// 🔥 어떤 타입이 와도 ms(number)로 바꿔주는 유틸 (Firestore Timestamp 대응)
const toMs = (v) => {
  if (v == null) return 0;

  // number(ms)
  if (typeof v === "number") return Number.isFinite(v) ? v : 0;

  // string(ISO 등)
  if (typeof v === "string") {
    const t = Date.parse(v);
    return Number.isNaN(t) ? 0 : t;
  }

  // Date
  if (v instanceof Date) return v.getTime();

  // Firestore Timestamp (toMillis)
  if (typeof v?.toMillis === "function") return v.toMillis();

  // Firestore Timestamp shape {seconds, nanoseconds}
  if (typeof v?.seconds === "number") return v.seconds * 1000;

  return 0;
};

// 🔥 “등록시간”을 뽑는 함수: createdAt 최우선, 없으면 updatedAt/등록일 fallback
const getCreatedMs = (r) => {
  return (
    toMs(r?.createdAt) ||
    toMs(r?.등록일시) ||
    toMs(r?.등록시간) ||
    toMs(r?.createdTime) ||
    toMs(r?.등록일 ? `${r.등록일}T00:00:00` : null)
  );
};
// ✅ ms → 보기 좋은 문자열(한국시간)
const formatKstDateTime = (ms) => {
  if (!ms) return "-";
  try {
    return new Date(ms).toLocaleString("ko-KR", {
      timeZone: "Asia/Seoul",
      hour12: false,
    });
  } catch {
    return "-";
  }
};

// ✅ 마지막 수정시간 후보(updatedAt / lastUpdated 등) 통합
const getUpdatedMs = (r) => {
  return (
    toMs(r?.updatedAt) ||
    toMs(r?.lastUpdated) ||
    toMs(r?.수정일시) ||
    toMs(r?.modifiedAt) ||
    0
  );
};

// ✅ 등록자 이름/식별자 후보 통합 (있는 것부터 표시)
const getCreatorLabel = (r) => {
  return (
    r?.등록자명 ||
    r?.createdByName ||
    r?.등록자 ||
    r?.createdByEmail ||
    r?.createdBy ||
    r?.createdByUid ||
    "-"
  );
};

// ✅ 최종: 상태순서 고정 + 같은 상태 안에서는 “등록시간(createdAt)” 최신순
const sortDispatchRows = (list = []) => {
  return [...list].sort((a, b) => {
    const ra = getStatusRank(a?.배차상태);
    const rb = getStatusRank(b?.배차상태);
    if (ra !== rb) return ra - rb;

    // 배차완료 → updatedAt 최신순 (수정시간 기준)
    if (a?.배차상태 === "배차완료") {
      return toMs(b?.updatedAt) - toMs(a?.updatedAt);
    }

    // 배차중 → createdAt 최신순 (등록시간 기준)
    return getCreatedMs(b) - getCreatedMs(a);
  });
};


