// 오전/오후 → 24시간 변환
// ------------------------
const normalizeTime = (t) => {
  if (!t) return "";

  let s = String(t).trim();

  // "오후 4시30분" → "오후 4:30"
  s = s.replace("시 ", ":")
       .replace("시", ":")
       .replace("분", "");

  // "오후 4:" → "오후 4:00"
  if (/:\s*$/.test(s)) s += "00";

  if (/^\d{1,2}:\d{2}$/.test(s)) {
    return s.padStart(5, "0");
  }

  const m = s.match(/(오전|오후)\s*(\d{1,2}):?(\d{2})?/);
  if (!m) return "";

  let [, ampm, hh, mm] = m;

  mm = mm ?? "00";
  hh = parseInt(hh, 10);

  if (ampm === "오후" && hh < 12) hh += 12;
  if (ampm === "오전" && hh === 12) hh = 0;

  return `${String(hh).padStart(2, "0")}:${String(mm).padStart(2, "0")}`;
};
const generateTimeOptions = () => {
  const result = [];
  for (let h = 0; h < 24; h++) {
    for (let m of [0, 30]) {
      const isPM = h >= 12;
      const hour12 = h % 12 === 0 ? 12 : h % 12;
      result.push(`${isPM ? "오후" : "오전"} ${hour12}시${m === 30 ? " 30분" : ""}`);
    }
  }
  return result;
};

