  // =====================
  const normalizeClient = (s = "") =>
    String(s)
      .normalize("NFC")
      .replace(/[\u200B-\u200D\uFEFF]/g, "") // zero-width 제거
      .replace(/\u00A0/g, " ")               // NBSP
      .toLowerCase()
      .trim()
      .replace(/\s+/g, "")
      .replace(/주식회사|유한회사|\(주\)|㈜/g, "")
      .replace(/\(.*?\)/g, "")
      .replace(/[0-9]/g, "")
      .replace(/[^a-z0-9가-힣]/g, "");
  // =====================
  // 🔽 정렬 비교 함수 (필수)
