    {/* 수정 저장 */}
    <button
  onClick={async () => {
    if (!copyTarget?._id) {
      showAlert("수정할 오더 ID가 없습니다.");
      return;
    }

    // ✅ 화물내용: 이미 onChange에서 동기화되어 있으므로 그대로 사용
    const finalCargo = copyTarget.화물내용 || "";

    const payload = {
      ...copyTarget,
      화물내용: finalCargo,
      updatedAt: Date.now(),
    };
    delete payload.createdAt;
    // ✅ 임시 UI 필드 제거 (DB에 저장하면 안 됨)
    delete payload.화물수량;
    delete payload.화물타입;
    delete payload.톤수값;
    delete payload.톤수타입;

const savedId = copyTarget._id;
    setCopyPanelOpen(false);
    showAlert("오더 수정 완료");

flashRow(savedId);
    setTimeout(() => {
      const el = document.getElementById(`row-${savedId}`);
      if (el) el.scrollIntoView({ behavior: "smooth", block: "center" });
    }, 400);

    patchDispatch(savedId, payload).catch(console.error);
    if (payload.상차지명) upsertPlace?.({ 업체명: payload.상차지명, 주소: payload.상차지주소||"", 담당자: payload.상차지담당자||"", 담당자번호: payload.상차지담당자번호||"" }).catch(console.error);
    if (payload.하차지명) upsertPlace?.({ 업체명: payload.하차지명, 주소: payload.하차지주소||"", 담당자: payload.하차지담당자||"", 담당자번호: payload.하차지담당자번호||"" }).catch(console.error);
    const plate = normalizePlate(payload.차량번호 || "");
    setRows(prev => prev.map(r => r._id === savedId ? { ...r, ...payload } : r));
  }}
  className="px-4 py-2 bg-emerald-600 text-white rounded-lg text-[13px] font-bold hover:bg-emerald-700 transition"
>
  수정 저장
</button>


    {/* 복사 등록 */}
<button
  onClick={async () => {
    if (!copyTarget) {
      showAlert("복사할 데이터가 없습니다.");
      return;
    }

    // ✅ 화물내용: 이미 onChange에서 동기화되어 있음
    const finalCargo = copyTarget.화물내용 || "";

    const payload = {
      ...copyTarget,
      화물내용: finalCargo,
      상차일: todayStr(),
      하차일: todayStr(),
      등록일: todayStr(),
      createdAt: Date.now(),
      updatedAt: Date.now(),
      배차상태:
        copyTarget?.차량번호?.trim()
          ? "배차완료"
          : "배차중",
      업체전달상태: "미전달",
    };

    delete payload._id;
    // ✅ 임시 UI 필드 제거
    delete payload.화물수량;
    delete payload.화물타입;
    delete payload.톤수값;
    delete payload.톤수타입;

    await setDoc(
      doc(db, copyTarget.__col || "orders", crypto.randomUUID()),
      payload
    );

    showAlert("복사 등록 완료");
    setCopyPanelOpen(false);
  }}
  className="px-4 py-2 bg-[#1B2B4B] text-white rounded-lg text-[13px] font-bold hover:bg-[#243a60] transition"
>
  복사 등록
</button>


