            {/* ------------------------------------------------ */}
            {/* 🔵 차량번호 (자동매칭) */}
            {/* ------------------------------------------------ */}
            <div className="mb-3">
              <label>차량번호</label>
              <input
                className="border p-2 rounded w-full"
                value={editTarget.차량번호 || ""}
                placeholder="예: 93가1234"
                onChange={(e) => {
                  const raw = e.target.value;
                  const clean = raw.replace(/\s+/g, "");
                  if (clean) {
                    const match = (drivers || []).find(d => String(d.차량번호 || "").replace(/\s+/g, "") === clean);
                    if (match) {
                      const grade = match?.등급 || match?.grade || "";
                      if (grade === "블랙") setBlackAlert(match);
                      else if (match?.메모 && String(match.메모).trim()) window.dispatchEvent(new CustomEvent("driverMemoDetected", { detail: match }));
                    }
                  }
                  setEditTarget((p) => ({
                    ...p,
                    차량번호: raw,
                    // 🔥 차량번호를 전부 지우면 기사정보도 즉시 제거
                    ...(raw.trim() === "" && {
                      이름: "",
                      전화번호: "",
                      배차상태: "배차중",
                    }),
                  }));
                }}
                onKeyDown={(e) => {
  if (e.key !== "Enter") return;

  const raw = e.target.value.trim();
  const clean = raw.replace(/\s+/g, "");
  if (!clean) return;

  const matches = drivers.filter(
    (d) => String(d.차량번호 || "").replace(/\s+/g, "") === clean
  );

  // 1명 → 바로 적용
  if (matches.length === 1) {
    const d = matches[0];
    const grade = d?.등급 || d?.grade || "";
    if (grade === "블랙") {
      setBlackAlert(d);
    }
    setEditTarget((p) => ({
      ...p,
      차량번호: raw,
      이름: d.이름 || "",
      전화번호: d.전화번호 || "",
      배차상태: "배차완료",
      updatedAt: Date.now(),
    }));
    setDriverPick(null);
    return;
  }

  // 여러 명 → 선택 UI 띄우기
  if (matches.length > 1) {
    setDriverPick({
      plate: raw,
      list: matches,
    });
    return;
  }

  // 0명 → 신규 등록 (단, 이미 이름이 있으면 스킵)
  if (editTarget?.이름?.trim()) return;

  const ok = window.confirm(
    `[${raw}] 등록된 기사가 없습니다.\n신규 기사로 추가할까요?`
  );
  if (!ok) return;


  const 이름 = prompt("기사명 입력");
  if (!이름) return;

const 전화번호 = prompt("전화번호 입력");
if (!전화번호) return;

// 🔥 1. 포맷 적용 (UI용)
const formattedPhone = formatPhone(전화번호);

// 🔥 2. 숫자만 추출 (DB 저장용)
const rawPhone = formattedPhone.replace(/[^\d]/g, "");

  upsertDriver({
  차량번호: raw,
  이름,
  전화번호: rawPhone, // DB는 숫자만
});

setEditTarget((p) => ({
  ...p,
  차량번호: raw,
  이름,
  전화번호: formattedPhone, // UI는 하이픈 포함
  배차상태: "배차완료",
  updatedAt: Date.now(),
}));
}}
              />
              {driverPick && (
  <div className="mt-2 border rounded-md bg-white shadow-sm">
    <div className="px-3 py-1.5 text-xs font-semibold bg-slate-100 border-b">
      동일 차량번호 기사 선택
    </div>

    {driverPick.list.map((d) => (
      <button
        key={d.id}
        type="button"
        className="w-full text-left px-3 py-2 text-sm hover:bg-blue-50 border-b last:border-b-0"
        onClick={() => {
          setEditTarget((p) => ({
            ...p,
            차량번호: driverPick.plate,
            이름: d.이름,
            전화번호: d.전화번호,
            배차상태: "배차완료",
          }));
          setDriverPick(null);
        }}
      >
        <div className="font-medium">{d.이름}</div>
        <div className="text-xs text-gray-500">{d.전화번호}</div>
      </button>
    ))}
  </div>
)}
            </div>

