// ===================== 손익보고서 컴포넌트 =====================
function ProfitLossReport({ dispatchData = [], fixedRows = [] }) {
  const currentYear = new Date().getFullYear();
  const [year, setYear] = React.useState(currentYear);
  const [manualData, setManualData] = React.useState({});
  const [saving, setSaving] = React.useState(false);
  const [editingCell, setEditingCell] = React.useState(null); // { rowKey, month }
  const [importPreview, setImportPreview] = React.useState(null); // { parsed, fileName }

  const toInt = (v) => parseInt(String(v || "0").replace(/[^\d-]/g, ""), 10) || 0;

  const MONTHS = ["01","02","03","04","05","06","07","08","09","10","11","12"];
  const MONTH_LABELS = ["1월","2월","3월","4월","5월","6월","7월","8월","9월","10월","11월","12월"];

  // Firestore 수동 데이터 로드
  React.useEffect(() => {
    async function load() {
      try {
        const snap = await getDoc(doc(db, "plManual", String(year)));
        if (snap.exists()) {
          setManualData(snap.data().rows || {});
        } else {
          setManualData({});
        }
      } catch (e) {
        console.error("손익보고서 로드 오류:", e);
      }
    }
    load();
  }, [year]);

  // 수동 데이터 저장
  const saveManual = async (newData) => {
    setSaving(true);
    try {
      await setDoc(doc(db, "plManual", String(year)), { rows: newData });
    } catch (e) {
      console.error("손익보고서 저장 오류:", e);
    } finally {
      setSaving(false);
    }
  };

  const updateCell = (rowKey, month, value) => {
    const numVal = parseInt(String(value).replace(/[^\d-]/g, ""), 10) || 0;
    const updated = {
      ...manualData,
      [rowKey]: { ...(manualData[rowKey] || {}), [month]: numVal },
    };
    setManualData(updated);
    saveManual(updated);
  };

  // 배차 데이터에서 월별 집계
  const dispatchRows = Array.isArray(dispatchData)
    ? dispatchData.filter((r) => (r.배차상태 || "") === "배차완료")
    : [];
  const fixedMapped = (fixedRows || []).map((r) => ({
    상차일: r.날짜,
    청구운임: toInt(r.청구운임),
    기사운임: toInt(r.기사운임),
    배차방식: r.배차방식 || "",
    차량종류: r.차량종류 || "",
    배차상태: "배차완료",
    지급방식: r.지급방식 || "",
    실수수료: toInt(r.실수수료 != null ? r.실수수료 : (Number(r.수수료||0) - Number(r.선결제||0))),
    거래처명: r.거래처명 || "",
    __isFixed: true,
  }));
  const allRows = [...dispatchRows.map((r) => ({ ...r, 청구운임: toInt(r.청구운임), 기사운임: toInt(r.기사운임) })), ...fixedMapped];

  const getAutoMonth = React.useMemo(() => {
    const result = {};
    const addRow = (key, month, sale, cost) => {
      if (!result[key]) result[key] = {};
      if (!result[key][month]) result[key][month] = { sale: 0, cost: 0 };
      result[key][month].sale += sale;
      result[key][month].cost += cost;
    };
    allRows.forEach((r) => {
      if (!r.상차일) return;
      const rowYear = r.상차일.slice(0, 4);
      if (rowYear !== String(year)) return;
      const month = r.상차일.slice(5, 7);
      const sale = r.청구운임 || 0;
      const cost = r.기사운임 || 0;
      const bm = r.배차방식 || "";
      const client = String(r.거래처명 || "");
      const pay = String(r.지급방식 || "");

      // ── 매출 분류 ──
      if (client.includes("후레쉬물류")) {
        addRow("rev_fresh", month, sale, 0);
      } else if (pay === "선불" || pay === "착불") {
        const cashAmt = r.__isFixed ? (r.실수수료 || 0) : Math.max(0, sale - cost);
        addRow("rev_cash", month, cashAmt, 0);
      } else {
        addRow("rev_freight", month, sale, 0);
      }

      // ── 매출원가(기사운임) 분류 ──
      if (bm === "인성") {
        addRow("cost_auto", month, 0, cost);
      } else if (client.includes("후레쉬물류")) {
        addRow("cost_fresh", month, 0, cost);
      } else {
        addRow("cost_freight", month, 0, cost);
      }
    });
    return result;
  }, [allRows, year]);

  const autoVal = (key, month, field = "sale") => {
    return (getAutoMonth[key] && getAutoMonth[key][month] && getAutoMonth[key][month][field]) || 0;
  };
  const manVal = (key, month) => (manualData[key] && manualData[key][month]) || 0;

  // 행별 월 합계
  const rowMonthTotal = (key, isAuto = false, field = "sale") => {
    return MONTHS.reduce((s, m) => s + (isAuto ? autoVal(key, m, field) : manVal(key, m)), 0);
  };

  // 월별 집계 함수들
  const totalRevenue = (month) =>
    autoVal("rev_freight", month) + autoVal("rev_cash", month) +
    autoVal("rev_fresh", month) + manVal("rev_etc", month);

  const totalCost = (month) =>
    autoVal("cost_freight", month, "cost") + autoVal("cost_auto", month, "cost") +
    autoVal("cost_fresh", month, "cost") + manVal("cost_labor", month);

  const grossProfit = (month) => totalRevenue(month) - totalCost(month);

  const sgaTotal = (month) =>
    ["sga_rent","sga_util","sga_comm","sga_ins","sga_repair","sga_fuel",
     "sga_adv","sga_welfare","sga_tax","sga_depr","sga_entertainment","sga_office","sga_misc"].reduce((s, k) => s + manVal(k, month), 0);

  const opProfit = (month) => grossProfit(month) - sgaTotal(month);

  const otherNet = (month) => manVal("other_income", month) - manVal("other_expense", month);

  const netProfit = (month) => opProfit(month) + otherNet(month);

  const won = (v) => {
    if (v === 0) return "–";
    return (v < 0 ? "-" : "") + Math.abs(Math.round(v)).toLocaleString();
  };

  const pct = (profit, revenue) => {
    if (!revenue) return "–";
    return (profit / revenue * 100).toFixed(1) + "%";
  };

  // 연간 합계
  const yearTotal = (fn) => MONTHS.reduce((s, m) => s + fn(m), 0);

  const cellClass = (v) => {
    if (v === 0) return "text-gray-300";
    return v > 0 ? "text-gray-800" : "text-rose-600";
  };

  const ManualCell = ({ rowKey, month }) => {
    const isEditing = editingCell && editingCell.rowKey === rowKey && editingCell.month === month;
    const val = manVal(rowKey, month);
    if (isEditing) {
      return (
        <td className="px-1 py-0.5 text-center border-r border-gray-100">
          <input
            type="number"
            defaultValue={val || ""}
            className="w-full text-center text-[12px] border border-blue-400 rounded px-1 outline-none"
            autoFocus
            onBlur={(e) => {
              updateCell(rowKey, month, e.target.value);
              setEditingCell(null);
            }}
            onKeyDown={(e) => {
              if (e.key === "Enter") { e.preventDefault(); e.stopPropagation(); updateCell(rowKey, month, e.target.value); setEditingCell(null); }
              if (e.key === "Escape") { e.preventDefault(); setEditingCell(null); }
            }}
          />
        </td>
      );
    }
    return (
      <td
        className="px-1 py-0.5 text-center border-r border-gray-100 cursor-pointer hover:bg-blue-50 text-[12px] text-gray-700"
        onClick={() => setEditingCell({ rowKey, month })}
      >
        {val ? val.toLocaleString() : ""}
      </td>
    );
  };

  const AutoCell = ({ rowKey, month, field = "sale" }) => {
    const val = autoVal(rowKey, month, field);
    return (
      <td className={`px-1 py-0.5 text-center border-r border-gray-100 text-[12px] ${val ? "text-gray-700" : "text-gray-200"}`}>
        {val ? val.toLocaleString() : ""}
      </td>
    );
  };

  const CalcCell = ({ value, highlight = false }) => (
    <td className={`px-1 py-0.5 text-center border-r border-gray-100 text-[12px] font-semibold ${
      highlight ? (value >= 0 ? "text-emerald-700" : "text-rose-600") : cellClass(value)
    }`}>
      {value !== 0 ? value.toLocaleString() : "–"}
    </td>
  );

  const RateCell = ({ profit, revenue }) => (
    <td className={`px-1 py-0.5 text-center border-r border-gray-100 text-[11px] font-medium ${
      revenue ? (profit / revenue >= 0 ? "text-emerald-600" : "text-rose-500") : "text-gray-300"
    }`}>
      {pct(profit, revenue)}
    </td>
  );

  const momPct = (calcFn, month) => {
    const mIdx = MONTHS.indexOf(month);
    if (mIdx === 0) return null;
    const cur = calcFn(month);
    if (!cur) return null; // 이번 달 데이터 없으면 표시 안함
    const prev = calcFn(MONTHS[mIdx - 1]);
    if (!prev) return null;
    return ((cur - prev) / Math.abs(prev)) * 100;
  };

  const MomRow = ({ calcFn }) => (
    <tr className="border-t border-gray-50">
      <td className="px-3 py-0.5 text-[10px] text-gray-400 whitespace-nowrap border-r border-gray-200 pl-8">전월대비</td>
      {MONTHS.map(m => {
        const p = momPct(calcFn, m);
        if (p === null) return <td key={m} className="px-1 py-0.5 text-center border-r border-gray-100 text-[10px] text-gray-300">–</td>;
        const isPos = p >= 0;
        return (
          <td key={m} className="px-1 py-0.5 text-center border-r border-gray-100 text-[10px] font-semibold"
            style={{ color: isPos ? "#ef4444" : "#3b82f6" }}>
            {isPos ? "▲" : "▼"}{Math.abs(p).toFixed(1)}%
          </td>
        );
      })}
      <td className="px-1 py-0.5 border-r border-gray-100"/>
    </tr>
  );

  const SectionHeader = ({ label, bg = "#1B2B4B" }) => (
    <tr style={{backgroundColor: bg}}>
      <td colSpan={14} className="px-4 py-2 text-[13px] font-bold text-white tracking-widest uppercase">{label}</td>
    </tr>
  );

  const SubHeader = ({ label, note = "" }) => (
    <tr className="bg-gray-100 border-t border-gray-200">
      <td className="px-3 py-1 text-[12px] font-semibold text-gray-700 whitespace-nowrap border-r border-gray-200 w-[140px]">
        {label}
        {note && <span className="ml-1 text-[10px] text-gray-400 font-normal">{note}</span>}
      </td>
      {MONTHS.map((m, i) => (
        <td key={m} className="px-1 py-1 text-center text-[11px] text-gray-400 font-medium border-r border-gray-200 w-[72px]">
          {MONTH_LABELS[i]}
        </td>
      ))}
      <td className="px-1 py-1 text-center text-[11px] text-gray-500 font-bold w-[80px]">합계</td>
    </tr>
  );

  const DataRow = ({ label, rowKey, isAuto = false, field = "sale", calcFn, isPct = false, isHighlight = false, indent = 0 }) => (
    <tr className="border-t border-gray-100 hover:bg-gray-50">
      <td className={`px-3 py-1 text-[12px] text-gray-600 whitespace-nowrap border-r border-gray-200 ${indent ? "pl-6" : ""}`}>
        {label}
      </td>
      {MONTHS.map((m) => {
        if (calcFn && isPct) return <RateCell key={m} profit={calcFn(m)} revenue={totalRevenue(m)} />;
        if (calcFn) return <CalcCell key={m} value={calcFn(m)} highlight={isHighlight} />;
        if (isAuto) return <AutoCell key={m} rowKey={rowKey} month={m} field={field} />;
        return <ManualCell key={m} rowKey={rowKey} month={m} />;
      })}
      <td className="px-1 py-0.5 text-center text-[12px] font-semibold text-gray-800">
        {calcFn && isPct
          ? pct(yearTotal(calcFn), yearTotal(totalRevenue))
          : calcFn
            ? (yearTotal(calcFn) !== 0 ? yearTotal(calcFn).toLocaleString() : "–")
            : isAuto
              ? (rowMonthTotal(rowKey, true, field) ? rowMonthTotal(rowKey, true, field).toLocaleString() : "–")
              : (rowMonthTotal(rowKey, false) !== 0 ? rowMonthTotal(rowKey, false).toLocaleString() : "–")
        }
      </td>
    </tr>
  );

  const TotalRow = ({ label, calcFn, isHighlight = false, isPct = false, bold = true }) => (
    <tr className="bg-gray-50 border-t-2 border-gray-300">
      <td className={`px-3 py-1.5 text-[12px] border-r border-gray-200 ${bold ? "font-bold text-gray-900" : "font-semibold text-gray-700"}`}>
        {label}
      </td>
      {MONTHS.map((m) => {
        const val = calcFn(m);
        if (isPct) return <RateCell key={m} profit={calcFn(m)} revenue={totalRevenue(m)} />;
        return (
          <td key={m} className={`px-1 py-1 text-center border-r border-gray-100 text-[12px] ${bold ? "font-bold" : "font-semibold"} ${
            isHighlight ? (val >= 0 ? "text-emerald-700" : "text-rose-600") : cellClass(val)
          }`}>
            {val !== 0 ? val.toLocaleString() : "–"}
          </td>
        );
      })}
      <td className={`px-1 py-1 text-center text-[12px] ${bold ? "font-bold" : "font-semibold"} ${
        isPct ? "" : isHighlight
          ? (yearTotal(calcFn) >= 0 ? "text-emerald-700" : "text-rose-600")
          : cellClass(yearTotal(calcFn))
      }`}>
        {isPct ? pct(yearTotal(calcFn), yearTotal(totalRevenue)) : (yearTotal(calcFn) !== 0 ? yearTotal(calcFn).toLocaleString() : "–")}
      </td>
    </tr>
  );

  const SGA_ITEMS = [
    { key: "sga_rent",          label: "임차료" },
    { key: "sga_util",          label: "공과금(전기/수도/가스)" },
    { key: "sga_comm",          label: "통신비" },
    { key: "sga_ins",           label: "보험료" },
    { key: "sga_repair",        label: "수선유지비" },
    { key: "sga_fuel",          label: "유류비" },
    { key: "sga_adv",           label: "광고선전비" },
    { key: "sga_welfare",       label: "복리후생비" },
    { key: "sga_tax",           label: "세금과공과" },
    { key: "sga_depr",          label: "감가상각비" },
    { key: "sga_entertainment", label: "접대비" },
    { key: "sga_office",        label: "사무용품비" },
    { key: "sga_misc",          label: "기타 판관비" },
  ];

  const VALID_MANUAL_KEYS = [
    "rev_etc","cost_labor","sga_rent","sga_util","sga_comm","sga_ins",
    "sga_repair","sga_fuel","sga_adv","sga_welfare","sga_tax","sga_depr",
    "sga_entertainment","sga_office","sga_misc","other_income","other_expense",
  ];

  const LABEL_TO_KEY = {
    // 매출
    "기타 매출": "rev_etc", "기타매출": "rev_etc",
    // 원가
    "인건비": "cost_labor",
    // 판관비
    "임차료": "sga_rent", "차량임차료": "sga_rent",
    "공과금(전기/수도/가스)": "sga_util", "공과금": "sga_util",
    "통신비": "sga_comm",
    "보험료": "sga_ins", "보험료(산재+고용)": "sga_ins",
    "수선유지비": "sga_repair", "차량유지비": "sga_repair",
    "유류비": "sga_fuel",
    "광고선전비": "sga_adv",
    "복리후생비": "sga_welfare",
    "세금과공과": "sga_tax", "세금과공과금": "sga_tax",
    "감가상각비": "sga_depr",
    "접대비": "sga_entertainment",
    "사무용품비": "sga_office",
    "소모품비": "sga_misc", "기타 판관비": "sga_misc", "기타판관비": "sga_misc",
    // 영업외
    "영업외 수익": "other_income", "영업외수익": "other_income",
    "영업외 비용": "other_expense", "영업외비용": "other_expense",
  };
  const KEY_TO_LABEL = {
    rev_etc: "기타 매출", cost_labor: "인건비", sga_rent: "차량임차료", sga_util: "공과금",
    sga_comm: "통신비", sga_ins: "보험료", sga_repair: "차량유지비", sga_fuel: "유류비",
    sga_adv: "광고선전비", sga_welfare: "복리후생비", sga_tax: "세금과공과금",
    sga_depr: "감가상각비", sga_entertainment: "접대비", sga_office: "사무용품비",
    sga_misc: "소모품비/기타 판관비", other_income: "영업외 수익", other_expense: "영업외 비용",
  };

  const handleExcelUpload = async (file) => {
    if (!file) return;
    try {
      const XLSX = await import("xlsx");
      const data = await file.arrayBuffer();
      const wb = XLSX.read(data, { type: "array" });
      const sheet = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: "" });
      // Find header row — match "항 목", "항목", "구분", "rowKey" after stripping whitespace
      let headerRowIdx = -1;
      for (let i = 0; i < Math.min(rows.length, 15); i++) {
        const first = String(rows[i][0] || "").replace(/\s+/g, "");
        if (["항목","구분","rowKey"].includes(first)) { headerRowIdx = i; break; }
      }
      if (headerRowIdx < 0) { alert("헤더 행(항목/구분)을 찾을 수 없습니다.\n서식 다운로드 후 해당 형식으로 작성해 주세요."); return; }
      const headerRow = rows[headerRowIdx] || [];
      const monthCols = {};
      headerRow.forEach((cell, ci) => {
        const m = String(cell || "").trim().match(/^(\d{1,2})월$/);
        if (m) monthCols[ci] = String(parseInt(m[1])).padStart(2, "0");
      });
      if (Object.keys(monthCols).length === 0) { alert("월 컬럼(1월~12월)을 찾을 수 없습니다. 헤더 형식을 확인하세요."); return; }
      // Parse rows → preview items
      const parsed = {}; // key → { month → value }
      for (let i = headerRowIdx + 1; i < rows.length; i++) {
        const r = rows[i];
        const label = String(r[0] || "").trim();
        if (!label) continue;
        const key = LABEL_TO_KEY[label] || null;
        if (!key || !VALID_MANUAL_KEYS.includes(key)) continue;
        if (!parsed[key]) parsed[key] = {};
        Object.entries(monthCols).forEach(([ci, month]) => {
          const raw = r[ci];
          if (raw === "" || raw == null) return; // skip empty cells
          const v = parseFloat(String(raw).replace(/[^\d.-]/g, "")) || 0;
          parsed[key][month] = Math.round(v);
        });
      }
      if (Object.keys(parsed).length === 0) { alert("업로드할 수 있는 항목을 찾지 못했습니다.\n서식 다운로드 후 올바른 항목명으로 입력해 주세요."); return; }
      setImportPreview({ parsed, fileName: file.name });
    } catch (e) {
      console.error("엑셀 업로드 오류:", e);
      alert("파일 처리 중 오류가 발생했습니다: " + e.message);
    }
  };

  const applyImport = async () => {
    if (!importPreview) return;
    const updated = { ...manualData };
    Object.entries(importPreview.parsed).forEach(([key, months]) => {
      if (!updated[key]) updated[key] = {};
      Object.entries(months).forEach(([month, val]) => {
        updated[key][month] = val;
      });
    });
    setManualData(updated);
    setImportPreview(null);
    await saveManual(updated);
  };

  const downloadTemplate = async () => {
    const XLSX = await import("xlsx");
    const header = ["항목", "1월","2월","3월","4월","5월","6월","7월","8월","9월","10월","11월","12월"];
    const sectionRows = [
      ["[기타 매출]"],
      ["기타 매출"],
      ["[매출원가]"],
      ["인건비"],
      ["[판매비와 관리비]"],
      ["복리후생비"],
      ["접대비"],
      ["세금과공과금"],
      ["차량유지비"],
      ["차량임차료"],
      ["광고선전비"],
      ["사무용품비"],
      ["소모품비"],
      ["통신비"],
      ["보험료(산재+고용)"],
      ["[영업외]"],
      ["영업외 수익"],
      ["영업외 비용"],
    ].map(row => {
      if (row[0].startsWith("[")) return [row[0], ...Array(12).fill("")]; // section header
      return [...row, ...Array(12).fill("")];
    });
    const ws = XLSX.utils.aoa_to_sheet([header, ...sectionRows]);
    ws["!cols"] = [{ wch: 26 }, ...Array(12).fill({ wch: 11 })];
    // Bold section header rows
    const wbOut = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wbOut, ws, `${year}`);
    XLSX.writeFile(wbOut, `손익보고서_서식_${year}년.xlsx`);
  };

  return (
    <div className="px-8 py-6">
      {/* 헤더 */}
      <div className="flex items-center justify-between mb-5">
        <div>
          <h2 className="text-[16px] font-bold text-[#1B2B4B]">손익보고서</h2>
          <p className="text-[12px] text-gray-400 mt-0.5">자동 집계 항목 외 수동 입력 항목은 셀을 클릭하거나 엑셀로 업로드하세요</p>
        </div>
        <div className="flex items-center gap-2">
          {saving && <span className="text-[12px] text-blue-500">저장 중...</span>}
          <button onClick={downloadTemplate}
            className="px-3 py-1.5 text-[12px] font-semibold rounded-lg border border-gray-300 text-gray-600 hover:bg-gray-50 transition">
            서식 다운로드
          </button>
          <label className="px-3 py-1.5 text-[12px] font-semibold rounded-lg bg-[#1B2B4B] text-white hover:opacity-90 transition cursor-pointer">
            엑셀 업로드
            <input type="file" accept=".xlsx,.xls,.csv" className="hidden"
              onChange={e => { const f = e.target.files[0]; if (f) handleExcelUpload(f); e.target.value = ""; }} />
          </label>
          <div className="flex items-center gap-1 ml-2">
            <button onClick={() => setYear(y => y - 1)} className="px-2 py-1 rounded bg-gray-100 hover:bg-gray-200 text-[13px]">◀</button>
            <span className="px-3 py-1 font-bold text-[14px] text-[#1B2B4B]">{year}년</span>
            <button onClick={() => setYear(y => y + 1)} className="px-2 py-1 rounded bg-gray-100 hover:bg-gray-200 text-[13px]">▶</button>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-x-auto">
        <table className="min-w-full border-collapse text-[12px]">
          <tbody>

            {/* ── 매출 ── */}
            <SectionHeader label="매출" bg="#1B2B4B" />
            <SubHeader label="구분" />
            <DataRow label="화물주선 매출" rowKey="rev_freight" isAuto field="sale" indent={0} />
            <DataRow label="선착불 수수료" rowKey="rev_cash" isAuto field="sale" />
            <DataRow label="후레쉬물류 매출" rowKey="rev_fresh" isAuto field="sale" />
            <DataRow label="기타 매출" rowKey="rev_etc" />
            <TotalRow label="매출액 합계" calcFn={totalRevenue} />
            <MomRow calcFn={totalRevenue} />

            {/* ── 매출원가 ── */}
            <SectionHeader label="매출원가" />
            <SubHeader label="구분" />
            <DataRow label="화물주선 운반비" rowKey="cost_freight" isAuto field="cost" />
            <DataRow label="오토바이(인성) 운반비" rowKey="cost_auto" isAuto field="cost" />
            <DataRow label="후레쉬물류 운반비" rowKey="cost_fresh" isAuto field="cost" />
            <DataRow label="인건비" rowKey="cost_labor" />
            <TotalRow label="매출원가 합계" calcFn={totalCost} />
            <MomRow calcFn={totalCost} />

            {/* ── 매출총이익 ── */}
            <SectionHeader label="매출총이익" />
            <TotalRow label="매출총이익" calcFn={grossProfit} isHighlight />
            <MomRow calcFn={grossProfit} />
            <TotalRow label="매출총이익률" calcFn={grossProfit} isPct />

            {/* ── 판매관리비 ── */}
            <SectionHeader label="판매관리비 (판관비)" />
            <SubHeader label="구분" />
            {SGA_ITEMS.map(({ key, label }) => (
              <DataRow key={key} label={label} rowKey={key} />
            ))}
            <TotalRow label="판관비 합계" calcFn={sgaTotal} />

            {/* ── 영업이익 ── */}
            <SectionHeader label="영업이익" />
            <TotalRow label="영업이익" calcFn={opProfit} isHighlight />
            <MomRow calcFn={opProfit} />
            <TotalRow label="영업이익률" calcFn={opProfit} isPct />

            {/* ── 영업외손익 ── */}
            <SectionHeader label="영업외손익" />
            <SubHeader label="구분" />
            <DataRow label="영업외 수익" rowKey="other_income" />
            <DataRow label="영업외 비용" rowKey="other_expense" />
            <TotalRow label="영업외손익 합계" calcFn={otherNet} bold={false} />

            {/* ── 당기순이익 ── */}
            <SectionHeader label="당기순이익" bg="#1B2B4B" />
            <TotalRow label="당기순이익" calcFn={netProfit} isHighlight />
            <MomRow calcFn={netProfit} />
            <TotalRow label="순이익률" calcFn={netProfit} isPct />

          </tbody>
        </table>
      </div>
      <p className="mt-3 text-[11px] text-gray-400">* 자동: 배차완료 기준 청구운임(매출) / 기사운임(운반비) 자동 집계 &nbsp;|&nbsp; 빈 셀 클릭 시 수동 입력 (Firestore 저장)</p>

      {/* ── 엑셀 업로드 미리보기 모달 ── */}
      {importPreview && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[99999]" onClick={() => setImportPreview(null)}>
          <div className="bg-white rounded-2xl shadow-2xl w-[680px] max-h-[85vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
            <div className="bg-[#1B2B4B] px-6 py-4 flex items-center justify-between shrink-0">
              <div>
                <div className="text-white font-bold text-[15px]">업로드 미리보기</div>
                <div className="text-white/50 text-[12px] mt-0.5">{importPreview.fileName} · {Object.keys(importPreview.parsed).length}개 항목 인식됨</div>
              </div>
              <button className="text-white/50 hover:text-white text-xl leading-none" onClick={() => setImportPreview(null)}>×</button>
            </div>
            <div className="overflow-y-auto flex-1 p-5">
              <table className="w-full text-[12px] border-collapse">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="text-left px-3 py-2 border border-gray-200 font-semibold text-gray-600 w-[160px]">항목</th>
                    {MONTH_LABELS.map((m, i) => (
                      <th key={m} className="px-1 py-2 border border-gray-200 font-semibold text-gray-600 text-center w-[44px]">{m}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {VALID_MANUAL_KEYS.map(key => {
                    const importedRow = importPreview.parsed[key];
                    if (!importedRow) return null;
                    const currentRow = manualData[key] || {};
                    const hasDiff = MONTHS.some(m => (importedRow[m] ?? null) !== null && importedRow[m] !== (currentRow[m] || 0));
                    return (
                      <tr key={key} className={hasDiff ? "bg-blue-50" : ""}>
                        <td className="px-3 py-1.5 border border-gray-100 font-semibold text-gray-700">{KEY_TO_LABEL[key] || key}</td>
                        {MONTHS.map(m => {
                          const imported = importedRow[m] ?? null;
                          const current = currentRow[m] || 0;
                          const changed = imported !== null && imported !== current;
                          return (
                            <td key={m} className={`px-1 py-1.5 border border-gray-100 text-right ${changed ? "text-[#1B2B4B] font-bold" : "text-gray-400"}`}>
                              {imported !== null ? (
                                <span>
                                  {changed && current !== 0 && <span className="text-gray-300 line-through text-[10px] block">{current.toLocaleString()}</span>}
                                  <span>{imported !== 0 ? imported.toLocaleString() : "–"}</span>
                                </span>
                              ) : ""}
                            </td>
                          );
                        })}
                      </tr>
                    );
                  }).filter(Boolean)}
                </tbody>
              </table>
              <p className="text-[11px] text-gray-400 mt-3">파란색 배경 = 변경되는 항목 · 굵은 글씨 = 현재 값과 다른 항목 · 취소선 = 기존 값</p>
            </div>
            <div className="px-6 py-4 border-t border-gray-100 flex gap-3 justify-end shrink-0">
              <button className="px-5 py-2 rounded-xl border border-gray-200 text-[13px] font-semibold text-gray-600 hover:bg-gray-50" onClick={() => setImportPreview(null)}>취소</button>
              <button className="px-5 py-2 rounded-xl bg-[#1B2B4B] text-white text-[13px] font-semibold hover:bg-[#243d6a]" onClick={applyImport}>적용</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ===================== 회계자료 컴포넌트 =====================
function AccountingDashboard({ dispatchData = [], fixedRows = [], clients = [] }) {
  const currentYear = new Date().getFullYear();
  const [subTab, setSubTab] = React.useState("ar");
  const [year, setYear] = React.useState(currentYear);
  const [arPayments, setArPayments] = React.useState({});
  const [apPayments, setApPayments] = React.useState({});
  const [arModal, setArModal] = React.useState(null);
  const [apModal, setApModal] = React.useState(null);
  const [arInput, setArInput] = React.useState("");
  const [apInput, setApInput] = React.useState("");
  const [saving, setSaving] = React.useState(false);
  const [vatQuarter, setVatQuarter] = React.useState("Q1");

  const toInt = (v) => parseInt(String(v || "0").replace(/[^\d-]/g, ""), 10) || 0;
  const MONTHS = ["01","02","03","04","05","06","07","08","09","10","11","12"];

  React.useEffect(() => {
    async function load() {
      try {
        const snap = await getDoc(doc(db, "acctPayments", String(year)));
        if (snap.exists()) {
          const d = snap.data();
          setArPayments(d.ar || {});
          setApPayments(d.ap || {});
        } else {
          setArPayments({});
          setApPayments({});
        }
      } catch (e) { console.error(e); }
    }
    load();
  }, [year]);

  const yearOrders = React.useMemo(() => {
    const all = [
      ...(dispatchData || []).filter(r => r.배차상태 === "배차완료"),
      ...(fixedRows || []).map(r => ({ ...r, 상차일: r.날짜, 배차상태: "배차완료" })),
    ];
    return all.filter(r => (r.상차일 || "").slice(0, 4) === String(year));
  }, [dispatchData, fixedRows, year]);

  const arByClient = React.useMemo(() => {
    const map = {};
    yearOrders.forEach(r => {
      const c = r.거래처명 || r.상차지명 || "미분류";
      if (!map[c]) map[c] = { invoiced: 0, oldest: null };
      map[c].invoiced += toInt(r.청구운임);
      const d = r.상차일;
      if (d && (!map[c].oldest || d < map[c].oldest)) map[c].oldest = d;
    });
    return Object.entries(map).map(([c, v]) => {
      const paid = arPayments[c] || 0;
      const outstanding = Math.max(0, v.invoiced - paid);
      const ageDays = v.oldest ? Math.floor((Date.now() - new Date(v.oldest)) / 86400000) : 0;
      return { client: c, invoiced: v.invoiced, paid, outstanding, ageDays };
    }).sort((a, b) => b.outstanding - a.outstanding);
  }, [yearOrders, arPayments]);

  const apByDriver = React.useMemo(() => {
    const map = {};
    yearOrders.forEach(r => {
      const d = r.이름 || "미지정";
      if (!map[d]) map[d] = { total: 0, carNo: r.차량번호 || "" };
      map[d].total += toInt(r.기사운임);
    });
    return Object.entries(map).map(([d, v]) => {
      const paid = apPayments[d] || 0;
      return { driver: d, carNo: v.carNo, total: v.total, paid, outstanding: Math.max(0, v.total - paid) };
    }).sort((a, b) => b.outstanding - a.outstanding);
  }, [yearOrders, apPayments]);

  const vatData = React.useMemo(() => {
    const m = {};
    MONTHS.forEach(mo => { m[mo] = { sales: 0, costs: 0 }; });
    yearOrders.forEach(r => {
      const mo = (r.상차일 || "").slice(5, 7);
      if (m[mo]) { m[mo].sales += toInt(r.청구운임); m[mo].costs += toInt(r.기사운임); }
    });
    const quarters = { Q1: [0,1,2], Q2: [3,4,5], Q3: [6,7,8], Q4: [9,10,11] };
    const qData = {};
    Object.entries(quarters).forEach(([q, idxs]) => {
      const mos = idxs.map(i => MONTHS[i]);
      qData[q] = {
        sales: mos.reduce((s, mo) => s + m[mo].sales, 0),
        costs: mos.reduce((s, mo) => s + m[mo].costs, 0),
        months: mos.map(mo => ({ mo, ...m[mo] })),
      };
    });
    return { monthly: m, quarters: qData };
  }, [yearOrders]);

  const costByType = React.useMemo(() => {
    const map = {};
    yearOrders.forEach(r => {
      const t = r.차량종류 || "미분류";
      if (!map[t]) map[t] = { sales: 0, costs: 0, count: 0 };
      map[t].sales += toInt(r.청구운임);
      map[t].costs += toInt(r.기사운임);
      map[t].count++;
    });
    return Object.entries(map).map(([t, v]) => ({
      type: t, ...v,
      profit: v.sales - v.costs,
      margin: v.sales > 0 ? (v.sales - v.costs) / v.sales * 100 : 0,
    })).sort((a, b) => b.sales - a.sales);
  }, [yearOrders]);

  const costByMethod = React.useMemo(() => {
    const map = {};
    yearOrders.forEach(r => {
      const t = r.배차방식 || "직접";
      if (!map[t]) map[t] = { sales: 0, costs: 0, count: 0 };
      map[t].sales += toInt(r.청구운임);
      map[t].costs += toInt(r.기사운임);
      map[t].count++;
    });
    return Object.entries(map).map(([t, v]) => ({
      method: t, ...v,
      profit: v.sales - v.costs,
      margin: v.sales > 0 ? (v.sales - v.costs) / v.sales * 100 : 0,
    })).sort((a, b) => b.sales - a.sales);
  }, [yearOrders]);

  const totalInvoiced = arByClient.reduce((s, r) => s + r.invoiced, 0);
  const totalArPaid = arByClient.reduce((s, r) => s + r.paid, 0);
  const totalAr = arByClient.reduce((s, r) => s + r.outstanding, 0);
  const totalAp = apByDriver.reduce((s, r) => s + r.total, 0);
  const totalApPaid = apByDriver.reduce((s, r) => s + r.paid, 0);
  const totalApOutstanding = apByDriver.reduce((s, r) => s + r.outstanding, 0);

  const won = (v) => v === 0 ? "–" : (v < 0 ? "-" : "") + Math.abs(Math.round(v)).toLocaleString();

  const ageLabel = (days) => {
    if (days <= 30) return { label: "30일 이내", color: "#374151" };
    if (days <= 60) return { label: "31~60일", color: "#b45309" };
    if (days <= 90) return { label: "61~90일", color: "#c2410c" };
    return { label: "90일 초과", color: "#b91c1c" };
  };

  const savePayment = async (type, name, amtStr) => {
    const amt = parseInt(String(amtStr).replace(/[^\d]/g, ""), 10) || 0;
    if (!amt) return;
    setSaving(true);
    try {
      const newAr = type === "ar" ? { ...arPayments, [name]: (arPayments[name] || 0) + amt } : arPayments;
      const newAp = type === "ap" ? { ...apPayments, [name]: (apPayments[name] || 0) + amt } : apPayments;
      await setDoc(doc(db, "acctPayments", String(year)), { ar: newAr, ap: newAp });
      setArPayments(newAr);
      setApPayments(newAp);
    } catch (e) { console.error(e); } finally { setSaving(false); }
  };

  const resetPayment = async (type, name) => {
    if (!window.confirm(`${name} 의 ${type === "ar" ? "수금" : "지급"} 내역을 초기화하시겠습니까?`)) return;
    setSaving(true);
    try {
      const newAr = type === "ar" ? { ...arPayments, [name]: 0 } : arPayments;
      const newAp = type === "ap" ? { ...apPayments, [name]: 0 } : apPayments;
      await setDoc(doc(db, "acctPayments", String(year)), { ar: newAr, ap: newAp });
      setArPayments(newAr);
      setApPayments(newAp);
    } catch (e) { console.error(e); } finally { setSaving(false); }
  };

  const exportVatExcel = async () => {
    const XLSX = await import("xlsx");
    const qd = vatData.quarters[vatQuarter];
    const moLabels = { "01":"1월","02":"2월","03":"3월","04":"4월","05":"5월","06":"6월","07":"7월","08":"8월","09":"9월","10":"10월","11":"11월","12":"12월" };
    const header = ["월","공급가액(매출)","매출세액(10%)","매입공급가액","매입세액(10%)","납부세액"];
    const rows = qd.months.map(({ mo, sales, costs }) => [
      moLabels[mo], sales, Math.round(sales * 0.1), costs, Math.round(costs * 0.1), Math.round(sales * 0.1) - Math.round(costs * 0.1),
    ]);
    const totalRow = ["합계", qd.sales, Math.round(qd.sales*0.1), qd.costs, Math.round(qd.costs*0.1), Math.round(qd.sales*0.1)-Math.round(qd.costs*0.1)];
    const ws = XLSX.utils.aoa_to_sheet([header, ...rows, totalRow]);
    ws["!cols"] = [{ wch: 8 }, ...Array(5).fill({ wch: 16 })];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, `부가세_${year}_${vatQuarter}`);
    XLSX.writeFile(wb, `부가세신고자료_${year}_${vatQuarter}.xlsx`);
  };

  const KpiCard = ({ label, value, sub, highlight }) => (
    <div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 10, padding: "16px 20px" }}>
      <div className="text-[11px] font-bold text-gray-400 uppercase tracking-wide mb-1">{label}</div>
      <div className={`text-[20px] font-bold ${highlight === "danger" ? "text-red-600" : highlight === "ok" ? "text-emerald-700" : "text-[#1B2B4B]"}`}>
        {value}
      </div>
      {sub && <div className="text-[11px] text-gray-400 mt-1">{sub}</div>}
    </div>
  );

  const thStyle = { padding: "8px 12px", textAlign: "left", fontSize: 11, fontWeight: 700, color: "#6b7280", letterSpacing: ".06em", textTransform: "uppercase", borderBottom: "1px solid #e5e7eb", whiteSpace: "nowrap", background: "#f8f9fb" };
  const tdStyle = { padding: "9px 12px", fontSize: 13, color: "#374151", borderBottom: "1px solid #f0f2f5" };
  const tdR = { ...tdStyle, textAlign: "right" };

  const currentQData = vatData.quarters[vatQuarter] || { sales: 0, costs: 0, months: [] };
  const vatOutput = Math.round(currentQData.sales * 0.1);
  const vatInput = Math.round(currentQData.costs * 0.1);
  const vatNet = vatOutput - vatInput;

  return (
    <div className="px-8 py-6">
      <div className="flex items-center justify-between mb-5">
        <div>
          <h2 className="text-[16px] font-bold text-[#1B2B4B]">회계자료</h2>
          <p className="text-[12px] text-gray-400 mt-0.5">미수금·지급현황·부가세·원가분석을 한 곳에서 관리하세요</p>
        </div>
        <div className="flex items-center gap-2">
          {saving && <span className="text-[12px] text-blue-500">저장 중...</span>}
          <div className="flex items-center gap-1">
            <button onClick={() => setYear(y => y - 1)} className="px-2 py-1 rounded bg-gray-100 hover:bg-gray-200 text-[13px]">◀</button>
            <span className="px-3 py-1 font-bold text-[14px] text-[#1B2B4B]">{year}년</span>
            <button onClick={() => setYear(y => y + 1)} className="px-2 py-1 rounded bg-gray-100 hover:bg-gray-200 text-[13px]">▶</button>
          </div>
        </div>
      </div>

      {/* 서브탭 */}
      <div className="flex gap-0 border-b border-gray-200 mb-6">
        {[["ar","미수금 현황"],["ap","지급 현황"],["vat","부가세 자료"],["cost","원가 분석"]].map(([k, label]) => (
          <button key={k} onClick={() => setSubTab(k)}
            className={`px-5 py-2.5 text-[13px] font-semibold border-b-2 transition-colors ${subTab === k ? "border-[#1B2B4B] text-[#1B2B4B]" : "border-transparent text-gray-400 hover:text-gray-600"}`}>
            {label}
          </button>
        ))}
      </div>

      {/* ── 미수금 현황 ── */}
      {subTab === "ar" && (
        <div className="space-y-5">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <KpiCard label="총 청구액" value={`${won(totalInvoiced)}원`} />
            <KpiCard label="수금 완료" value={`${won(totalArPaid)}원`} highlight="ok" />
            <KpiCard label="미수금 잔액" value={`${won(totalAr)}원`} highlight={totalAr > 0 ? "danger" : "ok"} />
            <KpiCard label="미수금 비율" value={totalInvoiced > 0 ? `${(totalAr / totalInvoiced * 100).toFixed(1)}%` : "–"} sub="미수금 / 청구액" />
          </div>
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-x-auto">
            <table className="min-w-full border-collapse">
              <thead>
                <tr>
                  {["거래처","청구액","수금액","미수금","연체 구분",""].map((h, i) => (
                    <th key={i} style={{ ...thStyle, textAlign: i >= 1 && i <= 3 ? "right" : "left" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {arByClient.length === 0 ? (
                  <tr><td colSpan={6} style={{ ...tdStyle, textAlign: "center", color: "#9ca3af" }}>배차완료 데이터가 없습니다</td></tr>
                ) : arByClient.map(r => {
                  const age = ageLabel(r.ageDays);
                  return (
                    <tr key={r.client} style={{ background: r.outstanding > 0 ? "#fff" : "#f9fafb" }}>
                      <td style={tdStyle}><span className="font-semibold">{r.client}</span></td>
                      <td style={tdR}>{r.invoiced.toLocaleString()}</td>
                      <td style={tdR}>{r.paid > 0 ? r.paid.toLocaleString() : "–"}</td>
                      <td style={{ ...tdR, fontWeight: r.outstanding > 0 ? 700 : 400, color: r.outstanding > 0 ? "#b91c1c" : "#6b7280" }}>
                        {r.outstanding > 0 ? r.outstanding.toLocaleString() : "–"}
                      </td>
                      <td style={tdStyle}>
                        {r.outstanding > 0 ? <span style={{ fontSize: 12, fontWeight: 600, color: age.color }}>{age.label}</span> : <span style={{ fontSize: 12, color: "#10b981", fontWeight: 600 }}>수금완료</span>}
                      </td>
                      <td style={tdStyle}>
                        <div className="flex gap-1.5">
                          <button onClick={() => { setArModal(r.client); setArInput(""); }}
                            className="px-2.5 py-1 rounded-md bg-[#1B2B4B] text-white text-[11px] font-bold hover:opacity-80 transition">
                            입금 처리
                          </button>
                          {r.paid > 0 && (
                            <button onClick={() => resetPayment("ar", r.client)}
                              className="px-2 py-1 rounded-md border border-gray-200 text-gray-400 text-[11px] hover:bg-gray-50 transition">
                              초기화
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          <p className="text-[11px] text-gray-400">* 배차완료 기준 청구운임 합계. 입금 처리 시 Firestore에 저장됩니다.</p>
        </div>
      )}

      {/* ── 지급 현황 ── */}
      {subTab === "ap" && (
        <div className="space-y-5">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <KpiCard label="총 기사운임" value={`${won(totalAp)}원`} />
            <KpiCard label="지급 완료" value={`${won(totalApPaid)}원`} highlight="ok" />
            <KpiCard label="미지급 잔액" value={`${won(totalApOutstanding)}원`} highlight={totalApOutstanding > 0 ? "danger" : "ok"} />
            <KpiCard label="미지급 비율" value={totalAp > 0 ? `${(totalApOutstanding / totalAp * 100).toFixed(1)}%` : "–"} sub="미지급 / 기사운임" />
          </div>
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-x-auto">
            <table className="min-w-full border-collapse">
              <thead>
                <tr>
                  {["기사명","차량번호","기사운임 합계","지급액","미지급",""].map((h, i) => (
                    <th key={i} style={{ ...thStyle, textAlign: i >= 2 && i <= 4 ? "right" : "left" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {apByDriver.length === 0 ? (
                  <tr><td colSpan={6} style={{ ...tdStyle, textAlign: "center", color: "#9ca3af" }}>배차완료 데이터가 없습니다</td></tr>
                ) : apByDriver.map(r => (
                  <tr key={r.driver} style={{ background: r.outstanding > 0 ? "#fff" : "#f9fafb" }}>
                    <td style={tdStyle}><span className="font-semibold">{r.driver}</span></td>
                    <td style={tdStyle}>{r.carNo || "–"}</td>
                    <td style={tdR}>{r.total.toLocaleString()}</td>
                    <td style={tdR}>{r.paid > 0 ? r.paid.toLocaleString() : "–"}</td>
                    <td style={{ ...tdR, fontWeight: r.outstanding > 0 ? 700 : 400, color: r.outstanding > 0 ? "#b91c1c" : "#6b7280" }}>
                      {r.outstanding > 0 ? r.outstanding.toLocaleString() : "–"}
                    </td>
                    <td style={tdStyle}>
                      <div className="flex gap-1.5">
                        <button onClick={() => { setApModal(r.driver); setApInput(""); }}
                          className="px-2.5 py-1 rounded-md bg-[#1B2B4B] text-white text-[11px] font-bold hover:opacity-80 transition">
                          지급 처리
                        </button>
                        {r.paid > 0 && (
                          <button onClick={() => resetPayment("ap", r.driver)}
                            className="px-2 py-1 rounded-md border border-gray-200 text-gray-400 text-[11px] hover:bg-gray-50 transition">
                            초기화
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <p className="text-[11px] text-gray-400">* 배차완료 기준 기사운임 합계. 지급 처리 시 Firestore에 저장됩니다.</p>
        </div>
      )}

      {/* ── 부가세 자료 ── */}
      {subTab === "vat" && (
        <div className="space-y-5">
          <div className="flex items-center gap-3 flex-wrap">
            <span className="text-[13px] font-semibold text-gray-600">분기 선택</span>
            {["Q1","Q2","Q3","Q4"].map(q => (
              <button key={q} onClick={() => setVatQuarter(q)}
                className={`px-4 py-1.5 rounded-lg text-[13px] font-semibold border transition ${vatQuarter === q ? "bg-[#1B2B4B] text-white border-[#1B2B4B]" : "border-gray-300 text-gray-600 hover:bg-gray-50"}`}>
                {q} ({q === "Q1" ? "1~3월" : q === "Q2" ? "4~6월" : q === "Q3" ? "7~9월" : "10~12월"})
              </button>
            ))}
            <button onClick={exportVatExcel}
              className="ml-auto px-3 py-1.5 text-[12px] font-semibold rounded-lg bg-[#1B2B4B] text-white hover:opacity-90 transition">
              엑셀 내보내기
            </button>
          </div>

          {/* 분기 요약 */}
          <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            <KpiCard label="공급가액 (매출)" value={`${currentQData.sales.toLocaleString()}원`} />
            <KpiCard label="매출세액 (10%)" value={`${vatOutput.toLocaleString()}원`} />
            <KpiCard label="매입공급가액" value={`${currentQData.costs.toLocaleString()}원`} />
            <KpiCard label="매입세액 (10%)" value={`${vatInput.toLocaleString()}원`} />
            <KpiCard label="납부세액" value={`${vatNet.toLocaleString()}원`} highlight={vatNet > 0 ? "danger" : "ok"} sub="매출세액 – 매입세액" />
            <KpiCard label="과세 기준" value="일반과세" sub="10% 부가가치세 적용" />
          </div>

          {/* 월별 명세 */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-x-auto">
            <table className="min-w-full border-collapse">
              <thead>
                <tr>
                  {["월","공급가액(매출)","매출세액","매입공급가액","매입세액","납부세액"].map((h, i) => (
                    <th key={i} style={{ ...thStyle, textAlign: i === 0 ? "left" : "right" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {currentQData.months.map(({ mo, sales, costs }) => {
                  const vOut = Math.round(sales * 0.1);
                  const vIn = Math.round(costs * 0.1);
                  const vNet = vOut - vIn;
                  const moLabel = { "01":"1월","02":"2월","03":"3월","04":"4월","05":"5월","06":"6월","07":"7월","08":"8월","09":"9월","10":"10월","11":"11월","12":"12월" }[mo];
                  return (
                    <tr key={mo}>
                      <td style={{ ...tdStyle, fontWeight: 600 }}>{moLabel}</td>
                      <td style={tdR}>{sales > 0 ? sales.toLocaleString() : "–"}</td>
                      <td style={tdR}>{vOut > 0 ? vOut.toLocaleString() : "–"}</td>
                      <td style={tdR}>{costs > 0 ? costs.toLocaleString() : "–"}</td>
                      <td style={tdR}>{vIn > 0 ? vIn.toLocaleString() : "–"}</td>
                      <td style={{ ...tdR, fontWeight: 700, color: vNet > 0 ? "#b91c1c" : vNet < 0 ? "#059669" : "#374151" }}>
                        {vNet !== 0 ? vNet.toLocaleString() : "–"}
                      </td>
                    </tr>
                  );
                })}
                <tr style={{ background: "#f8f9fb", borderTop: "2px solid #e5e7eb" }}>
                  <td style={{ ...tdStyle, fontWeight: 800 }}>합계</td>
                  <td style={{ ...tdR, fontWeight: 800 }}>{currentQData.sales > 0 ? currentQData.sales.toLocaleString() : "–"}</td>
                  <td style={{ ...tdR, fontWeight: 800 }}>{vatOutput > 0 ? vatOutput.toLocaleString() : "–"}</td>
                  <td style={{ ...tdR, fontWeight: 800 }}>{currentQData.costs > 0 ? currentQData.costs.toLocaleString() : "–"}</td>
                  <td style={{ ...tdR, fontWeight: 800 }}>{vatInput > 0 ? vatInput.toLocaleString() : "–"}</td>
                  <td style={{ ...tdR, fontWeight: 800, color: vatNet > 0 ? "#b91c1c" : vatNet < 0 ? "#059669" : "#374151" }}>
                    {vatNet !== 0 ? vatNet.toLocaleString() : "–"}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
          <p className="text-[11px] text-gray-400">* 배차완료 청구운임을 과세표준(공급가액)으로, 기사운임을 매입가액으로 산정합니다. 실제 신고 시 세무사 확인을 권장합니다.</p>
        </div>
      )}

      {/* ── 원가 분석 ── */}
      {subTab === "cost" && (
        <div className="space-y-5">
          {/* 차량 종류별 */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="px-5 py-3 border-b border-gray-100 bg-[#1B2B4B]">
              <span className="text-[13px] font-bold text-white">차량 종류별 원가 분석</span>
            </div>
            <div className="overflow-x-auto">
              <table className="min-w-full border-collapse">
                <thead>
                  <tr>
                    {["차량 종류","건수","매출","원가(기사운임)","이익","이익률"].map((h, i) => (
                      <th key={i} style={{ ...thStyle, textAlign: i >= 1 ? "right" : "left" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {costByType.length === 0 ? (
                    <tr><td colSpan={6} style={{ ...tdStyle, textAlign: "center", color: "#9ca3af" }}>데이터 없음</td></tr>
                  ) : costByType.map(r => (
                    <tr key={r.type}>
                      <td style={{ ...tdStyle, fontWeight: 600 }}>{r.type}</td>
                      <td style={tdR}>{r.count.toLocaleString()}</td>
                      <td style={tdR}>{r.sales.toLocaleString()}</td>
                      <td style={tdR}>{r.costs.toLocaleString()}</td>
                      <td style={{ ...tdR, fontWeight: 700, color: r.profit >= 0 ? "#1B2B4B" : "#b91c1c" }}>{r.profit.toLocaleString()}</td>
                      <td style={{ ...tdR, fontWeight: 700, color: r.margin >= 15 ? "#059669" : r.margin >= 8 ? "#374151" : "#b91c1c" }}>
                        {r.margin.toFixed(1)}%
                      </td>
                    </tr>
                  ))}
                  {costByType.length > 0 && (() => {
                    const ts = costByType.reduce((s, r) => s + r.sales, 0);
                    const tc = costByType.reduce((s, r) => s + r.costs, 0);
                    const tp = ts - tc;
                    return (
                      <tr style={{ background: "#f8f9fb", borderTop: "2px solid #e5e7eb" }}>
                        <td style={{ ...tdStyle, fontWeight: 800 }}>합계</td>
                        <td style={{ ...tdR, fontWeight: 800 }}>{costByType.reduce((s, r) => s + r.count, 0).toLocaleString()}</td>
                        <td style={{ ...tdR, fontWeight: 800 }}>{ts.toLocaleString()}</td>
                        <td style={{ ...tdR, fontWeight: 800 }}>{tc.toLocaleString()}</td>
                        <td style={{ ...tdR, fontWeight: 800, color: tp >= 0 ? "#1B2B4B" : "#b91c1c" }}>{tp.toLocaleString()}</td>
                        <td style={{ ...tdR, fontWeight: 800, color: ts > 0 && tp/ts*100 >= 15 ? "#059669" : "#374151" }}>{ts > 0 ? (tp/ts*100).toFixed(1) : "0.0"}%</td>
                      </tr>
                    );
                  })()}
                </tbody>
              </table>
            </div>
          </div>

          {/* 배차방식별 */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="px-5 py-3 border-b border-gray-100 bg-[#1B2B4B]">
              <span className="text-[13px] font-bold text-white">배차 방식별 원가 분석</span>
            </div>
            <div className="overflow-x-auto">
              <table className="min-w-full border-collapse">
                <thead>
                  <tr>
                    {["배차 방식","건수","매출","원가","이익","이익률"].map((h, i) => (
                      <th key={i} style={{ ...thStyle, textAlign: i >= 1 ? "right" : "left" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {costByMethod.length === 0 ? (
                    <tr><td colSpan={6} style={{ ...tdStyle, textAlign: "center", color: "#9ca3af" }}>데이터 없음</td></tr>
                  ) : costByMethod.map(r => (
                    <tr key={r.method}>
                      <td style={{ ...tdStyle, fontWeight: 600 }}>{r.method}</td>
                      <td style={tdR}>{r.count.toLocaleString()}</td>
                      <td style={tdR}>{r.sales.toLocaleString()}</td>
                      <td style={tdR}>{r.costs.toLocaleString()}</td>
                      <td style={{ ...tdR, fontWeight: 700, color: r.profit >= 0 ? "#1B2B4B" : "#b91c1c" }}>{r.profit.toLocaleString()}</td>
                      <td style={{ ...tdR, fontWeight: 700, color: r.margin >= 15 ? "#059669" : r.margin >= 8 ? "#374151" : "#b91c1c" }}>
                        {r.margin.toFixed(1)}%
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* 월별 이익률 추이 */}
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="px-5 py-3 border-b border-gray-100 bg-[#1B2B4B]">
              <span className="text-[13px] font-bold text-white">월별 매출·이익 추이</span>
            </div>
            <div className="overflow-x-auto">
              <table className="min-w-full border-collapse">
                <thead>
                  <tr>
                    {["월","매출","원가","이익","이익률"].map((h, i) => (
                      <th key={i} style={{ ...thStyle, textAlign: i === 0 ? "left" : "right" }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {MONTHS.map((mo, idx) => {
                    const d = vatData.monthly[mo] || { sales: 0, costs: 0 };
                    const profit = d.sales - d.costs;
                    const margin = d.sales > 0 ? (profit / d.sales * 100) : 0;
                    return (
                      <tr key={mo} style={{ background: d.sales === 0 ? "#fafafa" : "#fff" }}>
                        <td style={{ ...tdStyle, fontWeight: 600, color: d.sales === 0 ? "#9ca3af" : "#374151" }}>{idx + 1}월</td>
                        <td style={{ ...tdR, color: d.sales === 0 ? "#d1d5db" : "#374151" }}>{d.sales > 0 ? d.sales.toLocaleString() : "–"}</td>
                        <td style={{ ...tdR, color: d.costs === 0 ? "#d1d5db" : "#374151" }}>{d.costs > 0 ? d.costs.toLocaleString() : "–"}</td>
                        <td style={{ ...tdR, fontWeight: profit !== 0 ? 700 : 400, color: profit > 0 ? "#1B2B4B" : profit < 0 ? "#b91c1c" : "#d1d5db" }}>
                          {profit !== 0 ? profit.toLocaleString() : "–"}
                        </td>
                        <td style={{ ...tdR, fontWeight: d.sales > 0 ? 700 : 400, color: margin >= 15 ? "#059669" : margin >= 8 ? "#374151" : d.sales > 0 ? "#b91c1c" : "#d1d5db" }}>
                          {d.sales > 0 ? `${margin.toFixed(1)}%` : "–"}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* 입금 처리 모달 */}
      {arModal && (
        <div className="fixed inset-0 bg-black/40 z-[99999] flex items-center justify-center p-4" onClick={() => setArModal(null)}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6" onClick={e => e.stopPropagation()}>
            <div className="font-bold text-[15px] text-[#1B2B4B] mb-1">입금 처리</div>
            <div className="text-[12px] text-gray-400 mb-4">{arModal}</div>
            <div className="mb-1 text-[12px] text-gray-500">미수금 잔액: <strong>{(arByClient.find(r => r.client === arModal)?.outstanding || 0).toLocaleString()}원</strong></div>
            <input
              type="number"
              value={arInput}
              onChange={e => setArInput(e.target.value)}
              placeholder="입금액 입력 (원)"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 text-[13px] mb-4 outline-none focus:border-[#1B2B4B]"
              autoFocus
            />
            <div className="flex gap-2 justify-end">
              <button onClick={() => setArModal(null)} className="px-4 py-2 rounded-lg border border-gray-200 text-[13px] text-gray-500 hover:bg-gray-50">취소</button>
              <button
                onClick={async () => { await savePayment("ar", arModal, arInput); setArModal(null); }}
                className="px-4 py-2 rounded-lg bg-[#1B2B4B] text-white text-[13px] font-bold hover:opacity-90"
              >
                저장
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 지급 처리 모달 */}
      {apModal && (
        <div className="fixed inset-0 bg-black/40 z-[99999] flex items-center justify-center p-4" onClick={() => setApModal(null)}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6" onClick={e => e.stopPropagation()}>
            <div className="font-bold text-[15px] text-[#1B2B4B] mb-1">지급 처리</div>
            <div className="text-[12px] text-gray-400 mb-4">{apModal}</div>
            <div className="mb-1 text-[12px] text-gray-500">미지급 잔액: <strong>{(apByDriver.find(r => r.driver === apModal)?.outstanding || 0).toLocaleString()}원</strong></div>
            <input
              type="number"
              value={apInput}
              onChange={e => setApInput(e.target.value)}
              placeholder="지급액 입력 (원)"
              className="w-full border border-gray-300 rounded-lg px-3 py-2 text-[13px] mb-4 outline-none focus:border-[#1B2B4B]"
              autoFocus
            />
            <div className="flex gap-2 justify-end">
              <button onClick={() => setApModal(null)} className="px-4 py-2 rounded-lg border border-gray-200 text-[13px] text-gray-500 hover:bg-gray-50">취소</button>
              <button
                onClick={async () => { await savePayment("ap", apModal, apInput); setApModal(null); }}
                className="px-4 py-2 rounded-lg bg-[#1B2B4B] text-white text-[13px] font-bold hover:opacity-90"
              >
                저장
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ===================== DispatchApp.jsx (PART 6/8 — Settlement Premium) — START =====================
function Settlement({ dispatchData, fixedRows = [], clients = [], places = [] }) {

  const [activeTab, setActiveTab] = React.useState("overview"); // overview | client_compare
  const [rangeStart, setRangeStart] = React.useState("2026-01");
  const [rangeEnd, setRangeEnd] = React.useState("2026-02");
  const [rangeClients, setRangeClients] = React.useState([]);
  const [clientSearch, setClientSearch] = React.useState("");
  const [targetMonth, setTargetMonth] = React.useState(
    new Date().toISOString().slice(0, 7)
  );
  const toggleClient = (c) => {
    setRangeClients((prev) =>
      prev.includes(c) ? prev.filter((v) => v !== c) : [...prev, c]
    );
  };
  const [selectedYear, setSelectedYear] = React.useState(
    new Date().getFullYear()
  );
  const [detailClient, setDetailClient] = React.useState(null);
  const [aiMode, setAiMode] = React.useState(null);

  const toInt = (v) =>
    parseInt(String(v || "0").replace(/[^\d-]/g, ""), 10) || 0;
  const sum = (list, key) => list.reduce((a, r) => a + toInt(r[key]), 0);
  const profitRate = (sale, profit) =>
    sale === 0 ? 0 : (profit / sale) * 100;
  const ratePct = (n) => `${n.toFixed(1)}%`;

  // ================================
  // 📸 매출관리 화면 전체 캡쳐 (PNG / PDF)
  // ================================
  const exportSettlementCapture = async (type = "png") => {
    const el = document.getElementById("settlement-capture");
    if (!el) { showAlert("캡쳐 영역을 찾을 수 없습니다."); return; }
    const canvas = await html2canvas(el, { scale: 2, useCORS: true, backgroundColor: "#ffffff" });
    if (type === "png") {
      const link = document.createElement("a");
      link.download = `매출관리_${targetMonth}.png`;
      link.href = canvas.toDataURL("image/png");
      link.click();
      return;
    }
    const imgData = canvas.toDataURL("image/png");
    const pdf = new jsPDF("p", "mm", "a4");
    const pdfWidth = 210;
    const pdfHeight = 297;
    const imgWidth = pdfWidth;
    const imgHeight = (canvas.height * imgWidth) / canvas.width;
    let heightLeft = imgHeight;
    let position = 0;
    pdf.addImage(imgData, "PNG", 0, position, imgWidth, imgHeight);
    heightLeft -= pdfHeight;
    while (heightLeft > 0) {
      position = heightLeft - imgHeight;
      pdf.addPage();
      pdf.addImage(imgData, "PNG", 0, position, imgWidth, imgHeight);
      heightLeft -= pdfHeight;
    }
    pdf.save(`매출관리_${targetMonth}.pdf`);
  };

  const [yearKey, monthNum] = targetMonth.split("-").map(Number);
  const monthKey = targetMonth;

  const kpiDay = (() => {
    const today = new Date();
    const maxDay = new Date(yearKey, monthNum, 0).getDate();
    const safeDay = Math.min(today.getDate(), maxDay);
    return `${targetMonth}-${String(safeDay).padStart(2, "0")}`;
  })();

  const prevMonthDate = new Date(yearKey, monthNum - 2, 1);
  const prevMonthKey = `${prevMonthDate.getFullYear()}-${String(
    prevMonthDate.getMonth() + 1
  ).padStart(2, "0")}`;

  const dispatchRows = Array.isArray(dispatchData)
    ? dispatchData
        .filter((r) => (r.배차상태 || "") === "배차완료")
        .map((r) => {
          const sale = toInt(r.청구운임);
          const driver = toInt(r.기사운임);
          return {
            ...r,
            수수료:
              r.수수료 !== undefined && r.수수료 !== null && String(r.수수료).trim() !== ""
                ? toInt(r.수수료)
                : Math.max(sale - driver, 0),
          };
        })
    : [];

  const fixedMapped = (fixedRows || []).map((r) => {
    const sale = toInt(r.청구운임);
    const driver = toInt(r.기사운임);
    const fee =
      r.수수료 !== undefined && r.수수료 !== null && String(r.수수료).trim() !== ""
        ? toInt(r.수수료)
        : Math.max(sale - driver, 0);
    return {
      상차일: r.날짜,
      출발지: r.출발지 || "",
      도착지: r.도착지 || "",
      거래처명: r.거래처명 || "",
      청구운임: sale,
      기사운임: driver,
      수수료: fee,
      배차상태: "배차완료",
    };
  });

  const rows = [...dispatchRows, ...fixedMapped];

  const allClients = React.useMemo(() => {
    return Array.from(
      new Set(
        [
          ...rows.map((r) => r.거래처명 || ""),
          ...clients.map((c) => c.거래처명 || ""),
          ...places.map((p) => p.업체명 || ""),
        ].filter(Boolean)
      )
    ).sort();
  }, [rows, clients, places]);

  const filteredClients = React.useMemo(() => {
    if (!clientSearch) return [];
    return allClients
      .filter((c) => c.toLowerCase().includes(clientSearch.toLowerCase()))
      .slice(0, 10);
  }, [clientSearch, allClients]);

  const rangeRows = rows.filter((r) => {
    if (!r.상차일) return false;
    const ym = r.상차일.slice(0, 7);
    if (ym < rangeStart || ym > rangeEnd) return false;
    if (rangeClients.length > 0) {
      const ok = rangeClients.some(
        (c) =>
          (r.거래처명 || "").includes(c) ||
          (r.상차지명 || "").includes(c) ||
          (r.하차지명 || "").includes(c)
      );
      if (!ok) return false;
    }
    return true;
  });

  const rangeMonthly = React.useMemo(() => {
    const map = {};
    rangeRows.forEach((r) => {
      const ym = r.상차일.slice(0, 7);
      if (!map[ym]) map[ym] = { ym, sale: 0, driver: 0, fee: 0 };
      map[ym].sale += toInt(r.청구운임);
      map[ym].driver += toInt(r.기사운임);
      map[ym].fee += toInt(r.수수료);
    });
    return Object.values(map).sort((a, b) => a.ym.localeCompare(b.ym));
  }, [rangeRows]);

  const rangeSummary = rangeMonthly.reduce(
    (a, r) => { a.sale += r.sale; a.driver += r.driver; a.fee += r.fee; return a; },
    { sale: 0, driver: 0, fee: 0 }
  );
  const rangeProfit = rangeSummary.fee;
  const rangeProfitRate = rangeSummary.sale === 0 ? 0 : (rangeSummary.fee / rangeSummary.sale) * 100;

  const dayRows = rows.filter((r) => (r.상차일 || "") === kpiDay);
  const monthRows = rows.filter((r) => (r.상차일 || "").startsWith(monthKey));

  const startKey = `${yearKey}-01-01`;
  const endKey = `${targetMonth}-${String(new Date(yearKey, monthNum, 0).getDate()).padStart(2, "0")}`;
  const yearRows = rows.filter((r) => {
    const d = r.상차일;
    if (!d) return false;
    return d >= startKey && d <= endKey;
  });

  const prevMonthRows = rows.filter((r) => (r.상차일 || "").startsWith(prevMonthKey));

  const isValidClientName = (c) => c && !/^2\d{1,2}년/.test(c) && !c.includes("후레쉬물류");
  const firstAppearMap = new Map();
  rows.forEach((r) => {
    const c = r.거래처명 || "";
    const d = r.상차일 || "";
    if (!isValidClientName(c) || !d) return;
    if (!firstAppearMap.has(c) || d < firstAppearMap.get(c)) firstAppearMap.set(c, d);
  });

  const newClients = [];
  firstAppearMap.forEach((firstDate, client) => {
    if (firstDate.startsWith(monthKey)) {
      const clientRows = monthRows.filter((r) => r.거래처명 === client);
      const sale = sum(clientRows, "청구운임");
      const driver = sum(clientRows, "기사운임");
      const fee = sum(clientRows, "수수료");
      const profit = sale - driver;
      newClients.push({ client, firstDate, cnt: clientRows.length, sale, profit, fee });
    }
  });

  const won = (n) => `${(n || 0).toLocaleString()}원`;
  const isFresh = (r) => String(r.거래처명 || "").includes("후레쉬물류");
  const isExcludedClient = (name = "") => name.includes("후레쉬물류") || name.includes("채석강");

  const stat = (list) => {
    const sale = sum(list, "청구운임");
    const driver = sum(list, "기사운임");
    const profit = sale - driver;
    return { sale, driver, profit };
  };

  const d = stat(dayRows);
  const m = stat(monthRows);
  const y = stat(yearRows);
  const pm = stat(prevMonthRows);

  const monthSummary = {
    sale: sum(monthRows, "청구운임"),
    driver: sum(monthRows, "기사운임"),
    fee: sum(monthRows, "수수료"),
  };
  const monthProfit = monthSummary.fee;
  const monthProfitRate = monthSummary.sale === 0 ? 0 : (monthProfit / monthSummary.sale) * 100;

  const today = new Date().toISOString().slice(0, 10);
  const daysInMonth = new Date(yearKey, monthNum, 0).getDate();
  const elapsedDays =
    new Set(monthRows.map((r) => r.상차일).filter((d) => d && d <= today)).size || 1;
  const curSale = m.sale;
  const curProfit = m.profit;
  const curCnt = monthRows.length;
  const avgSalePerDay = curSale / elapsedDays;
  const avgProfitPerDay = curProfit / elapsedDays;
  const avgCntPerDay = curCnt / elapsedDays;
  const forecast = {
    sale: Math.round(avgSalePerDay * daysInMonth),
    profit: Math.round(avgProfitPerDay * daysInMonth),
    count: Math.round(avgCntPerDay * daysInMonth),
  };

  const pmPure = stat(prevMonthRows.filter((r) => !isFresh(r)));
  const dPure = stat(dayRows.filter((r) => !isFresh(r)));
  const mPure = stat(monthRows.filter((r) => !isFresh(r)));
  const yPure = stat(yearRows.filter((r) => !isFresh(r)));

  const baseYear = yearKey - 1;
  const lastYearRows = rows.filter((r) => {
    const d = r.상차일;
    if (!d) return false;
    return d.startsWith(String(baseYear));
  });

  const lastYearFreshByMonth = Array.from({ length: 12 }, (_, i) => ({
    month: `${i + 1}월`,
    sale: 0,
    profit: 0,
  }));
  lastYearRows.forEach((r) => {
    if (!isFresh(r)) return;
    const d = r.상차일;
    if (!d) return;
    const mIdx = Number(d.slice(5, 7)) - 1;
    const sale = toInt(r.청구운임);
    const driver = toInt(r.기사운임);
    lastYearFreshByMonth[mIdx].sale += sale;
    lastYearFreshByMonth[mIdx].profit += sale - driver;
  });

  const lastYearPure = stat(lastYearRows.filter((r) => !isFresh(r)));
  const PURE_TARGET_2026 = 2098451820;
  const lastYearFresh = stat(lastYearRows.filter((r) => isFresh(r)));
  const yFresh = stat(yearRows.filter((r) => isFresh(r)));
  const FRESH_GROWTH_RATE = 0.03;
  const FRESH_TARGET_2026 = Math.round(lastYearFresh.sale * (1 + FRESH_GROWTH_RATE));
  const achieveRate = (cur, target) => (target > 0 ? (cur / target) * 100 : 0);
  const baseYearSale = lastYearPure.sale;
  const growth2026 = { conservative: 0.05, normal: 0.1, aggressive: 0.18 };
  const forecast2026 = {
    conservative: Math.round(baseYearSale * (1 + growth2026.conservative)),
    normal: Math.round(baseYearSale * (1 + growth2026.normal)),
    aggressive: Math.round(baseYearSale * (1 + growth2026.aggressive)),
  };

  const todayDate = new Date();
  const todayKey2 = todayDate.toISOString().slice(0, 10);
  const prevMonthSameDay = (() => {
    const y = todayDate.getFullYear();
    const mo = todayDate.getMonth();
    const dd = todayDate.getDate();
    const lastDay = new Date(y, mo, 0).getDate();
    return new Date(y, mo - 1, Math.min(dd, lastDay)).toISOString().slice(0, 10);
  })();

  const groupByClientDay = (list) => {
    const map = {};
    list.forEach((r) => {
      const c = r.거래처명 || "미지정";
      if (!map[c]) map[c] = { sale: 0, cnt: 0 };
      map[c].sale += toInt(r.청구운임);
      map[c].cnt += 1;
    });
    return map;
  };
  const todayMap = groupByClientDay(rows.filter((r) => r.상차일 === todayKey2));
  const prevMap = groupByClientDay(rows.filter((r) => r.상차일 === prevMonthSameDay));
  const dayDropTop10 = Object.keys({ ...todayMap, ...prevMap })
    .map((client) => {
      const t = todayMap[client] || { sale: 0, cnt: 0 };
      const p = prevMap[client] || { sale: 0, cnt: 0 };
      return { client, todaySale: t.sale, todayCnt: t.cnt, prevSale: p.sale, prevCnt: p.cnt, diff: t.sale - p.sale };
    })
    .filter((r) => r.diff < 0)
    .sort((a, b) => a.diff - b.diff)
    .slice(0, 10);

  const diffRate = (cur, prev) => (prev === 0 ? 0 : ((cur - prev) / prev) * 100);
  const vr = { month: diffRate(m.profit, pm.profit) };
  const vrPure = { month: diffRate(mPure.profit, pmPure.profit) };
  const rateText = (n) => `${n >= 0 ? "▲" : "▼"} ${Math.abs(n).toFixed(1)}%`;
  const rateClass = (n) => (n >= 0 ? "text-emerald-600" : "text-rose-600");

  // ================================
  // 🧩 UI RENDER
  // ================================
  return (
    <div id="settlement-capture" className="bg-gray-50 min-h-screen">

      {/* ================= 페이지 헤더 ================= */}
      <div className="bg-white px-8 py-6 border-b border-gray-200">
  <div className="flex items-center justify-between">
    <div>
      <h1 className="text-[20px] font-bold text-[#1B2B4B] tracking-tight">매출관리</h1>
      <p className="text-[12px] text-gray-400 mt-1">매출 · 수익 · 거래처 분석 리포트</p>
    </div>
    <div className="flex items-center gap-2">
      <button
        onClick={() => exportSettlementCapture("png")}
        className="px-4 py-2 rounded-lg bg-gray-100 text-gray-700 text-[13px] font-semibold hover:bg-gray-200 transition border border-gray-200"
      >
        PNG 캡쳐
      </button>
      <button
        onClick={() => exportSettlementCapture("pdf")}
        className="px-4 py-2 rounded-lg bg-indigo-600 text-white text-[13px] font-semibold hover:bg-indigo-500 transition"
      >
        PDF 저장
      </button>
      <button
        onClick={() => {

                const headers = ["상차일","거래처명","상차지명","하차지명","청구운임","기사운임","수수료","배차상태"];
                const csvRows = [headers.join(",")];
                monthRows.forEach((r) => {
                  csvRows.push(headers.map((h) => `"${String(r[h] || "").replace(/"/g, '""')}"`).join(","));
                });
                const blob = new Blob(["\uFEFF" + csvRows.join("\n")], { type: "text/csv;charset=utf-8;" });
                const url = URL.createObjectURL(blob);
                const a = document.createElement("a");
                a.href = url;
                a.download = `매출관리_${targetMonth}.csv`;
                a.click();
              }}
               className="px-4 py-2 rounded-lg bg-emerald-600 text-white text-[13px] font-semibold hover:bg-emerald-500 transition"
            >
              CSV 내보내기
            </button>
          </div>
        </div>
      </div>
{/* ================= 탭 네비게이션 ================= */}
      <div className="px-8 border-b border-gray-200 bg-white flex items-center">
        <div className="flex gap-0">
          {[
            { key: "overview", label: "매출 개요" },
            { key: "client_compare", label: "거래처 동향 분석" },
            { key: "profit_loss", label: "손익보고서" },
            { key: "accounting", label: "회계자료" },
          ].map(tab => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`px-5 py-3 text-[13px] font-semibold border-b-2 transition-colors ${
                activeTab === tab.key
                  ? "border-[#1B2B4B] text-[#1B2B4B]"
                  : "border-transparent text-gray-400 hover:text-gray-600"
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
        <div className="ml-auto">
          <div className="bg-white rounded-xl border border-gray-200 px-4 py-2 flex items-center gap-3">
            <span className="text-[12px] text-gray-500">당월 수익률</span>
            <span className={`text-[16px] font-bold ${monthProfitRate >= 15 ? "text-emerald-600" : monthProfitRate >= 10 ? "text-blue-600" : "text-rose-600"}`}>
              {monthProfitRate.toFixed(1)}%
            </span>
            <div className="w-px h-5 bg-gray-200" />
            <span className="text-[12px] text-gray-500">당월 수익</span>
            <span className="text-[16px] font-bold text-emerald-600">
              {monthProfit.toLocaleString()}원
            </span>
          </div>
        </div>
      </div>


      {/* ================= 거래처 동향 분석 탭 ================= */}
      {activeTab === "client_compare" && (
        <ClientCompareDashboard
          dispatchData={dispatchData}
          places={places}
          fixedRows={fixedRows}
          clients={clients}
        />
      )}
      {/* ================= 손익보고서 탭 ================= */}
      {activeTab === "profit_loss" && (
        <ProfitLossReport
          dispatchData={dispatchData}
          fixedRows={fixedRows}
        />
      )}
      {/* ================= 회계자료 탭 ================= */}
      {activeTab === "accounting" && (
        <AccountingDashboard
          dispatchData={dispatchData}
          fixedRows={fixedRows}
          clients={clients}
        />
      )}
{/* ================= 매출 개요 탭 ================= */}
      {activeTab === "overview" && (
      <div className="px-8 py-6 grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">

        {/* ================= LEFT PANEL ================= */}
        <div className="space-y-6 flex-1">

          <SettlementMonthlyHeader
            targetMonth={targetMonth}
            setTargetMonth={setTargetMonth}
            monthRows={monthRows}
            forecast={forecast}
            forecast2026={forecast2026}
          />

          {/* ================= 🎯 연간 목표 대비 실적 · 2026 매출 전망 ================= */}
          <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="bg-[#1B2B4B] px-6 py-4">
              <h3 className="text-[15px] font-bold text-white">연간 목표 대비 실적 · 2026 매출 전망</h3>
              <p className="text-[11px] text-white/50 mt-0.5">전년 대비 성장 분석 및 시나리오 예측</p>
            </div>
            <div className="p-6 space-y-8">

              {/* 순수 운송 매출 */}
              <div className="rounded-xl border border-gray-200 bg-gray-50 p-5">
                <p className="text-sm font-semibold text-gray-800 mb-4">순수 운송 매출</p>
                <div className="grid grid-cols-4 gap-4 text-center">
                  <Metric label="작년" value={won(lastYearPure.sale)} />
                  <Metric label="목표" value={won(PURE_TARGET_2026)} valueClass="text-indigo-700" />
                  <Metric label="현재" value={won(yPure.sale)} valueClass="text-gray-900" />
                  <Metric label="달성률" value={`${achieveRate(yPure.sale, PURE_TARGET_2026).toFixed(1)}%`} valueClass="text-indigo-800" />
                </div>
              </div>

              {/* 후레쉬 물류 매출 */}
              <div className="rounded-xl border border-gray-200 bg-gray-50 p-5">
                <p className="text-sm font-semibold text-gray-700 mb-4">후레쉬 물류 매출</p>
                <div className="grid grid-cols-4 gap-4 text-center">
                  <Metric label="작년" value={won(lastYearFresh.sale)} />
                  <Metric label="목표" value={won(FRESH_TARGET_2026)} valueClass="text-indigo-700" />
                  <Metric label="현재" value={won(yFresh.sale)} valueClass="text-gray-900" />
                  <Metric label="달성률" value={`${achieveRate(yFresh.sale, FRESH_TARGET_2026).toFixed(1)}%`} valueClass="text-indigo-800" />
                </div>
              </div>

              {/* 구분선 */}
              <div className="flex items-center gap-3 pt-2">
                <span className="text-xs font-semibold text-gray-500">2026 매출 전망 (순수 운송)</span>
                <div className="flex-1 border-t border-gray-300" />
              </div>

              {/* 2026 매출 전망 */}
              <div className="grid grid-cols-3 gap-4 text-center">
                <ScenarioCard title="보수적 시나리오" value={forecast2026.conservative} tone="gray" />
                <ScenarioCard title="기준 시나리오" value={forecast2026.normal} tone="indigo" highlight />
                <ScenarioCard title="공격적 시나리오" value={forecast2026.aggressive} tone="gray" />
              </div>

            </div>
          </div>

          {/* ================= KPI – 총 운송료 ================= */}
          <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="bg-[#1B2B4B] px-6 py-3 flex items-center justify-between">
              <h3 className="text-[14px] font-bold text-white">총 운송료 (후레쉬 포함)</h3>
              <span className="text-[11px] text-white/40">배차 + 고정거래처</span>
            </div>
            <div className="p-6">
              <table className="w-full text-[13px] border-collapse text-center">
                <thead className="bg-gray-50 text-gray-600">
                  <tr>
                    <th className="border p-2">구분</th>
                    <th className="border p-2">매출</th>
                    <th className="border p-2">운반비</th>
                    <th className="border p-2">수익</th>
                    <th className="border p-2">수익률</th>
                    <th className="border p-2">전월대비</th>
                  </tr>
                </thead>
                <tbody>
                  {[
                    ["월", m, "month"],
                    ["년", y, null],
                  ].map(([label, data, key], i) => (
                    <tr key={i} className="font-semibold">
                      <td className="border p-2 bg-gray-50">{label}</td>
                      <td className="border p-2 text-indigo-700">{won(data.sale)}</td>
                      <td className="border p-2 text-gray-600">{won(data.driver)}</td>
                      <td className="border p-2 text-emerald-600">{won(data.profit)}</td>
                      <td className="border p-2 text-indigo-700">{ratePct(profitRate(data.sale, data.profit))}</td>
                      <td className={`border p-2 ${key ? rateClass(vr[key]) : "text-gray-400"}`}>
                        {key ? rateText(vr[key]) : "—"}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* ================= KPI – 순수 운송 ================= */}
          <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
            <div className="bg-[#1B2B4B] px-6 py-3">
              <h3 className="text-[14px] font-bold text-white">순수 운송료 (후레쉬 미포함)</h3>
            </div>
            <div className="p-6">
              <table className="w-full text-[13px] border-collapse text-center">
                <thead className="bg-gray-50 text-gray-600">
                  <tr>
                    <th className="border p-2">구분</th>
                    <th className="border p-2">매출</th>
                    <th className="border p-2">운반비</th>
                    <th className="border p-2">수익</th>
                    <th className="border p-2">수익률</th>
                    <th className="border p-2">전월대비</th>
                  </tr>
                </thead>
                <tbody>
                  {[
                    ["일", dPure, null],
                    ["월", mPure, "month"],
                    ["년", yPure, null],
                  ].map(([label, data, key], i) => (
                    <tr key={i} className="font-semibold">
                      <td className="border p-2 bg-gray-50">{label}</td>
                      <td className="border p-2 text-indigo-700">{won(data.sale)}</td>
                      <td className="border p-2 text-gray-600">{won(data.driver)}</td>
                      <td className="border p-2 text-emerald-600">{won(data.profit)}</td>
                      <td className="border p-2 text-indigo-700">{ratePct(profitRate(data.sale, data.profit))}</td>
                      <td className={`border p-2 ${key ? rateClass(vrPure[key]) : "text-gray-400"}`}>
                        {key ? rateText(vrPure[key]) : "—"}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <SettlementClientAnalysis
            topRows={monthRows.filter((r) => !isExcludedClient(r.거래처명))}
            dropRows={rows.filter((r) => !isExcludedClient(r.거래처명))}
            newClients={newClients}
            targetMonth={targetMonth}
          />

        </div>

        {/* ================= RIGHT PANEL ================= */}
        <div className="flex flex-col gap-6 flex-1">

          {/* 연간 요약 차트 */}
          <div className="flex-1 space-y-6">

            <YearlySummaryChart
              rows={rows}
              year={selectedYear}
              setYear={setSelectedYear}
              onAI={(mode) => setAiMode(mode)}
            />

            {/* 기간별 추이 */}
            <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
              <div className="bg-[#1B2B4B] px-6 py-4">
                <h3 className="text-[15px] font-bold text-white">기간별 매출 · 운임 · 수수료 추이</h3>
                <p className="text-[11px] text-white/50 mt-0.5">거래처별 필터링 및 월별 트렌드 분석</p>
              </div>
              <div className="p-6 space-y-5">

                {/* 조회 조건 */}
                <div className="grid grid-cols-3 gap-3">
                  <input
                    type="month"
                    value={rangeStart}
                    onChange={(e) => setRangeStart(e.target.value)}
                    className="border border-gray-200 rounded-lg p-2 text-[13px] focus:outline-none focus:border-blue-400"
                  />
                  <input
                    type="month"
                    value={rangeEnd}
                    onChange={(e) => setRangeEnd(e.target.value)}
                    className="border border-gray-200 rounded-lg p-2 text-[13px] focus:outline-none focus:border-blue-400"
                  />
                  <div className="col-span-3 space-y-3">
                    <div className="text-[12px] font-semibold text-gray-600">거래처 검색</div>
                    <input
                      type="text"
                      placeholder="거래처 검색 (예: 태영, 케이씨)"
                      value={clientSearch}
                      onChange={(e) => setClientSearch(e.target.value)}
                      className="border border-gray-200 rounded-lg p-2 text-[13px] w-full focus:outline-none focus:border-blue-400"
                    />
                    {clientSearch && (
                      <div className="flex flex-wrap gap-2">
                        {allClients
                          .filter((c) => c.toLowerCase().includes(clientSearch.toLowerCase()))
                          .slice(0, 10)
                          .map((c) => (
                            <button
                              key={c}
                              onClick={() => toggleClient(c)}
                              className="px-3 py-1 text-xs rounded-full border bg-white text-gray-700 border-gray-300 hover:bg-gray-100 transition"
                            >
                              {c}
                            </button>
                          ))}
                      </div>
                    )}
                    {rangeClients.length > 0 && (
                      <div className="flex flex-wrap gap-2">
                        {rangeClients.map((c) => (
                          <button
                            key={c}
                            onClick={() => toggleClient(c)}
                            className="px-3 py-1 text-xs rounded-full bg-indigo-600 text-white border border-indigo-600"
                          >
                            {c} ✕
                          </button>
                        ))}
                      </div>
                    )}
                    <div className="text-[11px] text-gray-400">선택: {rangeClients.length}개</div>
                  </div>
                </div>

                <PeriodTrendChart data={rangeMonthly} />
                <PeriodSummaryTable data={rangeMonthly} />

              </div>
            </div>

            {/* 스마트 인사이트 */}
            <SalesInsightPanel monthRows={monthRows} allRows={rows} targetMonth={targetMonth} />

            {/* 요일별 수주 분석 */}
            <WeekdayAnalysisChart monthRows={monthRows} />


          </div>
        </div>

        {/* ================= DETAIL POPUP ================= */}
        {detailClient && (
          <SettlementDetailPopup
            client={detailClient}
            rows={monthRows.filter((r) => r.거래처명 === detailClient)}
            onClose={() => setDetailClient(null)}
          />
        )}
        {aiMode && (
          <AIInsightModal
            mode={aiMode}
            monthRows={monthRows}
            forecast2026={forecast2026}
            onClose={() => setAiMode(null)}
          />
        )}

</div>
      )} {/* overview tab end */}
    </div>
  );
}

/* ================================================================= */
/* ================== 서브 컴포넌트 ================================== */
/* ================================================================= */

function PeriodTrendChart({ data = [] }) {
  if (!data.length) {
    return (
      <div className="h-[260px] flex items-center justify-center text-[13px] text-gray-400">
        조회된 데이터가 없습니다
      </div>
    );
  }
  return (
    <div className="h-[260px]">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={data}>
          <Legend
            verticalAlign="top"
            align="right"
            iconType="circle"
            wrapperStyle={{ fontSize: 12, color: "#374151", paddingBottom: 8 }}
            formatter={(value) => {
              if (value === "sale") return "청구운임";
              if (value === "driver") return "기사운임";
              if (value === "fee") return "수수료";
              return value;
            }}
          />
          <CartesianGrid stroke="#E5E7EB" strokeDasharray="3 3" />
          <XAxis dataKey="ym" tick={{ fontSize: 11, fill: "#9CA3AF" }} axisLine={false} tickLine={false} />
          <YAxis tickFormatter={(v) => `${(v / 1_000_000).toFixed(0)}M`} tick={{ fontSize: 11, fill: "#9CA3AF" }} axisLine={false} tickLine={false} />
          <Tooltip
            contentStyle={{ background: "#fff", borderRadius: 12, border: "1px solid #E5E7EB", fontSize: 12 }}
            formatter={(v, n) => [
              `${v.toLocaleString()}원`,
              n === "sale" ? "청구운임" : n === "driver" ? "기사운임" : "수수료",
            ]}
          />
          <Line type="monotone" dataKey="sale" stroke="#6366F1" strokeWidth={2.5} dot={false} activeDot={{ r: 5 }} />
          <Line type="monotone" dataKey="driver" stroke="#10B981" strokeWidth={2} dot={false} />
          <Line type="monotone" dataKey="fee" stroke="#F59E0B" strokeWidth={2} dot={false} />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

function PeriodSummaryTable({ data = [] }) {
  if (!data.length) return null;
  const sumKey = (key) => data.reduce((a, r) => a + r[key], 0);
  const totalSale = sumKey("sale");
  const totalDriver = sumKey("driver");
  const totalFee = sumKey("fee");
  const totalRate = totalSale ? (totalFee / totalSale) * 100 : 0;

  return (
    <div className="overflow-auto">
      <table className="w-full text-[13px] border-collapse text-center">
        <thead className="bg-gray-50 text-gray-600">
          <tr>
            <th className="border p-2">월</th>
            <th className="border p-2">청구운임</th>
            <th className="border p-2">기사운임</th>
            <th className="border p-2">수수료(수익)</th>
            <th className="border p-2">수익률</th>
          </tr>
        </thead>
        <tbody>
          {data.map((r) => {
            const rate = r.sale ? (r.fee / r.sale) * 100 : 0;
            return (
              <tr key={r.ym} className="hover:bg-gray-50">
                <td className="border p-2 font-semibold">{r.ym}</td>
                <td className="border p-2 text-indigo-600">{r.sale.toLocaleString()}원</td>
                <td className="border p-2">{r.driver.toLocaleString()}원</td>
                <td className="border p-2 text-emerald-600 font-semibold">{r.fee.toLocaleString()}원</td>
                <td className="border p-2">{rate.toFixed(1)}%</td>
              </tr>
            );
          })}
          <tr className="font-bold bg-gray-100">
            <td className="border p-2">합계</td>
            <td className="border p-2 text-indigo-700">{totalSale.toLocaleString()}원</td>
            <td className="border p-2 text-gray-700">{totalDriver.toLocaleString()}원</td>
            <td className="border p-2 text-emerald-700">{totalFee.toLocaleString()}원</td>
            <td className="border p-2">{totalRate.toFixed(1)}%</td>
          </tr>
        </tbody>
      </table>
    </div>
  );
}

// ===================== 스마트 인사이트 =====================
function SalesInsightPanel({ monthRows = [], allRows = [], targetMonth = "" }) {
  const toInt = (v) => Number(String(v || "").replace(/[^\d]/g, "")) || 0;

  if (!monthRows.length) return null;

  const prevMonth = (() => {
    const d = new Date(targetMonth + "-01");
    d.setMonth(d.getMonth() - 1);
    return d.toISOString().slice(0, 7);
  })();
  const prevRows = allRows.filter(r => r.상차일?.startsWith(prevMonth));

  const totalSale = monthRows.reduce((s, r) => s + toInt(r.청구운임), 0);
  const prevSale = prevRows.reduce((s, r) => s + toInt(r.청구운임), 0);
  const growthPct = prevSale > 0 ? ((totalSale - prevSale) / prevSale * 100).toFixed(1) : null;

  // 건당 평균 운임
  const avgFare = monthRows.length > 0 ? Math.round(totalSale / monthRows.length) : 0;

  // 최고 거래처
  const byClient = {};
  monthRows.forEach(r => {
    const c = r.거래처명 || "미지정";
    byClient[c] = (byClient[c] || 0) + toInt(r.청구운임);
  });
  const topClient = Object.entries(byClient).sort((a, b) => b[1] - a[1])[0];

  // 수익률
  const totalFee = monthRows.reduce((s, r) => s + (toInt(r.청구운임) - toInt(r.기사운임)), 0);
  const profitRate = totalSale > 0 ? (totalFee / totalSale * 100).toFixed(1) : "0.0";

  const insights = [
    growthPct !== null ? {
      icon: parseFloat(growthPct) >= 0 ? "▲" : "▼",
      label: "전월 대비 매출",
      value: `${parseFloat(growthPct) >= 0 ? "+" : ""}${growthPct}%`,
      sub: `${Math.abs(totalSale - prevSale).toLocaleString()}원 ${parseFloat(growthPct) >= 0 ? "증가" : "감소"}`,
      positive: parseFloat(growthPct) >= 0,
    } : null,
    topClient ? {
      icon: "①",
      label: "이달 최고 거래처",
      value: topClient[0],
      sub: `${topClient[1].toLocaleString()}원 · 점유 ${Math.round(topClient[1]/totalSale*100)||0}%`,
      positive: true,
    } : null,
    {
      icon: "≈",
      label: "건당 평균 청구운임",
      value: `${avgFare.toLocaleString()}원`,
      sub: `총 ${monthRows.length}건 수주`,
      positive: true,
    },
    {
      icon: "%",
      label: "수익률",
      value: `${profitRate}%`,
      sub: `수익 ${totalFee.toLocaleString()}원`,
      positive: parseFloat(profitRate) >= 10,
    },
  ].filter(Boolean);

  return (
    <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
      <div className="bg-[#1B2B4B] px-6 py-4">
        <h3 className="text-[15px] font-bold text-white">스마트 인사이트</h3>
        <p className="text-[11px] text-white/50 mt-0.5">AI 기반 월별 분석 요약</p>
      </div>
      <div className="divide-y divide-gray-50">
        {insights.map((ins, i) => (
          <div key={i} className="flex items-center gap-4 px-6 py-3.5">
            <span className={`w-8 h-8 rounded-lg flex items-center justify-center text-[13px] font-bold shrink-0 ${ins.positive ? "bg-gray-100 text-gray-600" : "bg-rose-50 text-rose-500"}`}>{ins.icon}</span>
            <div className="flex-1 min-w-0">
              <div className="text-[11px] text-gray-400">{ins.label}</div>
              <div className={`text-[14px] font-bold truncate ${ins.positive ? "text-gray-800" : "text-rose-600"}`}>{ins.value}</div>
            </div>
            <div className="text-[11px] text-gray-400 text-right shrink-0">{ins.sub}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ===================== 요일별 수주 분석 =====================
function WeekdayAnalysisChart({ monthRows = [] }) {
  const toInt = (v) => Number(String(v || "").replace(/[^\d]/g, "")) || 0;

  if (!monthRows.length) return null;

  const days = ["일", "월", "화", "수", "목", "금", "토"];
  const byDay = Array(7).fill(null).map((_, i) => ({ day: days[i], 건수: 0, 매출: 0 }));

  monthRows.forEach(r => {
    if (!r.상차일) return;
    const d = new Date(r.상차일 + "T00:00:00");
    const dow = d.getDay();
    byDay[dow].건수 += 1;
    byDay[dow].매출 += toInt(r.청구운임);
  });

  const maxCount = Math.max(...byDay.map(d => d.건수), 1);

  return (
    <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
      <div className="bg-[#1B2B4B] px-6 py-4">
        <h3 className="text-[15px] font-bold text-white">요일별 수주 분석</h3>
        <p className="text-[11px] text-white/50 mt-0.5">어느 요일에 가장 많이 출하하는지 파악</p>
      </div>
      <div className="p-5">
        <div className="h-[200px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={byDay} barSize={28}>
              <CartesianGrid strokeDasharray="3 3" stroke="#E5E7EB" />
              <XAxis dataKey="day" tick={{ fontSize: 12, fill: "#374151" }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fontSize: 11, fill: "#9CA3AF" }} axisLine={false} tickLine={false} allowDecimals={false} />
              <Tooltip
                contentStyle={{ borderRadius: 10, fontSize: 12 }}
                formatter={(v, n) => [n === "매출" ? `${v.toLocaleString()}원` : `${v}건`, n]}
              />
              <Legend verticalAlign="top" align="right" iconType="circle" wrapperStyle={{ fontSize: 12 }} />
              <Bar dataKey="건수" fill="#6366F1" radius={[4, 4, 0, 0]}>
                {byDay.map((entry, i) => (
                  <Cell key={i} fill={entry.건수 === maxCount ? "#4F46E5" : "#A5B4FC"} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
        <div className="mt-3 grid grid-cols-7 gap-1 text-center text-[11px]">
          {byDay.map((d, i) => (
            <div key={i} className={`rounded-lg py-1.5 ${d.건수 === maxCount ? "bg-indigo-100 text-indigo-800 font-bold" : "bg-gray-50 text-gray-500"}`}>
              <div className="font-bold">{d.day}</div>
              <div>{d.건수}건</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}


